const safeLS = {
  get: (k, def = "") => { try { return isBrowser ? (localStorage.getItem(k) || def) : def; } catch { return def; } },
  set: (k, v) => { try { if (isBrowser) localStorage.setItem(k, String(v)); } catch {} },
};

