// ═══════════════════════════════════════════════
//  HUD CANVAS
// ═══════════════════════════════════════════════
function useHUDCanvas(hudStateRef) {
  const canvasRef = useRef(null);
  const animRef = useRef(null);
  const tRef = useRef(0);
  const lastFrameRef = useRef(0);
  
  // Particle Simulation Data
  const P_COUNT = 120;
  const particlesRef = useRef(Array.from({length: P_COUNT}, () => ({
    x: Math.random() * (typeof window !== "undefined" ? window.innerWidth : 1000),
    y: Math.random() * (typeof window !== "undefined" ? window.innerHeight : 1000),
    vx: (Math.random() - 0.5) * 1.2,
    vy: (Math.random() - 0.5) * 1.2,
    r: Math.random() * 1.5 + 0.5,
    glow: Math.random() * 0.5 + 0.2
  })));

  useEffect(() => {
    const canvas = canvasRef.current; if(!canvas) return;
    const ctx = canvas.getContext("2d");
    let W, H, CX, CY;
    const resize = () => { W=canvas.width=window.innerWidth; H=canvas.height=window.innerHeight; CX=Math.floor(W/2); CY=Math.floor(H/2); };
    window.addEventListener("resize", resize); resize();

    // ── Session start + Battery ──────────────────────────────────────────
    const sessionStartTime = Date.now();
    navigator.getBattery?.().then(b=>{
      hudStateRef.current.battery={level:b.level,charging:b.charging};
      b.addEventListener("levelchange",()=>{hudStateRef.current.battery={...hudStateRef.current.battery,level:b.level};});
      b.addEventListener("chargingchange",()=>{hudStateRef.current.battery={...hudStateRef.current.battery,charging:b.charging};});
    }).catch(()=>{});

    // ── Palette ─────────────────────────────────────────────────────────
    const PC = {
      BG:"#000308", PANEL:"rgba(0, 10, 25, 0.6)", BORDER:"rgba(0, 238, 255, 0.15)", BORDER2:"rgba(0, 150, 255, 0.1)",
      CYAN:"#00eeff", TEAL:"#00ffcc", TEAL_DIM:"#004455",
      GREEN:"#00ffa3", RED:"#ff2a55", AMBER:"#ffcc00",
      WHITE:"#ffffff", LABEL:"#66aaff", VALUE:"#ccffff", DIMTEXT:"#225577",
    };

    // ── Helpers ──────────────────────────────────────────────────────────
    const dt = (x,y,text,color,font='12px "Rajdhani"',align="left",base="middle") => {
      ctx.fillStyle=color; ctx.font=font; ctx.textAlign=align; ctx.textBaseline=base; ctx.fillText(text,x,y);
    };
    const glow = (x,y,text,color,font,align="center",blur=15) => {
      ctx.save(); ctx.shadowColor=color; ctx.shadowBlur=blur; dt(x,y,text,color,font,align); ctx.restore();
    };
    const bar = (x,y,w,h,pct,col) => {
      const rr=(bx,by,bw,bh,r)=>{ctx.beginPath();ctx.moveTo(bx+r,by);ctx.lineTo(bx+bw-r,by);ctx.quadraticCurveTo(bx+bw,by,bx+bw,by+r);ctx.lineTo(bx+bw,by+bh-r);ctx.quadraticCurveTo(bx+bw,by+bh,bx+bw-r,by+bh);ctx.lineTo(bx+r,by+bh);ctx.quadraticCurveTo(bx,by+bh,bx,by+bh-r);ctx.lineTo(bx,by+r);ctx.quadraticCurveTo(bx,by,bx+r,by);ctx.closePath();};
      rr(x,y,w,h,h/2); ctx.fillStyle="rgba(0, 15, 35, 0.6)"; ctx.fill();
      if(pct>0){rr(x,y,Math.max(h,pct/100*w),h,h/2); ctx.fillStyle=col; ctx.fill(); ctx.save(); ctx.shadowColor=col; ctx.shadowBlur=10; ctx.fill(); ctx.restore();}
      rr(x,y,w,h,h/2); ctx.strokeStyle=PC.BORDER; ctx.lineWidth=1; ctx.stroke();
    };
    const spark = (x,y,w,h,prices,col) => {
      if(!prices||prices.length<2) return;
      const mn=Math.min(...prices),mx=Math.max(...prices),rng=mx-mn||1;
      const grad=ctx.createLinearGradient(x,y,x,y+h);
      grad.addColorStop(0,col+"80"); grad.addColorStop(1,col+"00");
      ctx.beginPath();
      prices.forEach((p,i)=>{const px=x+(i/(prices.length-1))*w,py=y+h-((p-mn)/rng)*h; i===0?ctx.moveTo(px,py):ctx.lineTo(px,py);});
      ctx.lineTo(x+w,y+h); ctx.lineTo(x,y+h); ctx.closePath(); ctx.fillStyle=grad; ctx.fill();
      ctx.beginPath();
      prices.forEach((p,i)=>{const px=x+(i/(prices.length-1))*w,py=y+h-((p-mn)/rng)*h; i===0?ctx.moveTo(px,py):ctx.lineTo(px,py);});
      ctx.save(); ctx.shadowColor=col; ctx.shadowBlur=8; ctx.strokeStyle=col; ctx.lineWidth=2; ctx.stroke(); ctx.restore();
    };
    const wave = (x,y,w,h,hist,col) => {
      if(!hist.length) return;
      const step=w/hist.length;
      ctx.beginPath();
      hist.forEach((v,i)=>{const px=x+i*step,py=y+h-(v/100)*h; i===0?ctx.moveTo(px,py):ctx.lineTo(px,py);});
      ctx.save(); ctx.shadowColor=col; ctx.shadowBlur=6; ctx.strokeStyle=col; ctx.lineWidth=1.5; ctx.stroke(); ctx.restore();
    };
    const garc = (cx,cy,r,startDeg,ext,color,lw) => {
      const s=((startDeg-90)*Math.PI)/180,e=((startDeg+ext-90)*Math.PI)/180;
      ctx.beginPath(); ctx.arc(cx,cy,r,s,e); ctx.strokeStyle=color; ctx.lineWidth=lw; ctx.stroke();
    };

    // ── Arc Reactor Image ───────────────────────────────────────────────────
    const arcImg = new Image();
    arcImg.src = "data:image/png;base64,";
    const drawReactor = (cx,cy,r,t) => {
      const pulse=Math.abs(Math.sin(t*3))*15;
      // ── Reactor image radius (defined first so background rings can hug it) ──
      const imgR = r - 2;
      // Outer dashed arcs — innermost sits right at the reactor edge, others fan outward
      for(let i=1;i<=3;i++){
        const r2=imgR+4+(i-1)*28,sp=t*(1/i)*.4;
        ctx.save(); ctx.shadowColor=`rgba(0,200,255,0.5)`; ctx.shadowBlur=10;
        ctx.strokeStyle=`rgba(0,238,255,${0.2-i*0.04})`; ctx.lineWidth=1;
        ctx.setLineDash([6,12]); ctx.beginPath(); ctx.arc(cx,cy,r2,sp,sp+Math.PI*2*(.65+i*.1)); ctx.stroke(); ctx.setLineDash([]); ctx.restore();
      }
      // Outer compass ring — pushed further out for the wide background ring presence
      const compR=imgR+96;
      for(let i=0;i<24;i++){
        const ang=(i/24)*Math.PI*2-t*.15,len=i%6===0?18:i%3===0?10:5;
        ctx.strokeStyle=i%6===0?PC.CYAN:i%3===0?PC.TEAL:PC.BORDER;
        ctx.lineWidth=i%6===0?2:i%3===0?1:.5;
        ctx.beginPath(); ctx.moveTo(cx+compR*Math.cos(ang),cy+compR*Math.sin(ang)); ctx.lineTo(cx+(compR+len)*Math.cos(ang),cy+(compR+len)*Math.sin(ang)); ctx.stroke();
      }
      // ── Draw Arc Reactor Image (static, no rotation) ──
      ctx.save();
      ctx.beginPath(); ctx.arc(cx,cy,imgR,0,Math.PI*2); ctx.clip();
      if(arcImg.complete && arcImg.naturalWidth>0){
        ctx.drawImage(arcImg, cx-imgR, cy-imgR, imgR*2, imgR*2);
      } else {
        ctx.fillStyle="rgba(0,10,30,0.95)"; ctx.fill();
      }
      ctx.restore();
      // Pulsing cyan glow ring over image
      ctx.save();
      ctx.shadowColor=PC.CYAN; ctx.shadowBlur=28+pulse;
      ctx.beginPath(); ctx.arc(cx,cy,imgR,0,Math.PI*2);
      ctx.strokeStyle=`rgba(0,238,255,${0.55+Math.sin(t*3)*0.2})`; ctx.lineWidth=2.5; ctx.stroke();
      ctx.restore();
      // ── Rotating outer ring overlays (drawn ON TOP of image edge) ──
      // Ring 1: toothed segments rotating clockwise
      const toothR = imgR * 0.93;
      ctx.save(); ctx.translate(cx,cy); ctx.rotate(t * 0.18);      for(let deg=0;deg<360;deg+=10){
        const rad=deg*Math.PI/180;
        const ri=toothR-5, ro=toothR+5;
        ctx.beginPath(); ctx.moveTo(ri*Math.cos(rad),ri*Math.sin(rad)); ctx.lineTo(ro*Math.cos(rad),ro*Math.sin(rad));
        ctx.strokeStyle=deg%40===0?PC.CYAN:PC.TEAL; ctx.lineWidth=deg%40===0?2.5:1; ctx.stroke();
      }
      ctx.restore();
      // Ring 2: dashed arc rotating counter-clockwise
      ctx.save(); ctx.translate(cx,cy); ctx.rotate(-t * 0.35);
      ctx.shadowColor="rgba(0,220,255,0.8)"; ctx.shadowBlur=10;
      ctx.strokeStyle=`rgba(0,238,255,0.7)`; ctx.lineWidth=3;
      ctx.setLineDash([12,8]);
      ctx.beginPath(); ctx.arc(0,0,imgR*0.96,0,Math.PI*2); ctx.stroke();
      ctx.setLineDash([]); ctx.restore();
      // Ring 3: bright segment sweep rotating clockwise (fast)
      ctx.save(); ctx.translate(cx,cy); ctx.rotate(t * 0.55);
      ctx.shadowColor=PC.CYAN; ctx.shadowBlur=18;
      ctx.strokeStyle=`rgba(0,255,255,0.85)`; ctx.lineWidth=4;
      ctx.beginPath(); ctx.arc(0,0,imgR*0.96, 0, Math.PI*0.35); ctx.stroke();
      ctx.strokeStyle=`rgba(0,255,255,0.25)`; ctx.lineWidth=2;
      ctx.beginPath(); ctx.arc(0,0,imgR*0.96, Math.PI*0.35, Math.PI*0.7); ctx.stroke();
      ctx.restore();
      // ── Bulb Glow from Center — pulses like a breathing light ──
      const bulbPulse = (Math.sin(t * 1.8) + 1) / 2;
      const bulbAlpha = 0.18 + bulbPulse * 0.38;
      const bulbRadius = imgR * (0.32 + bulbPulse * 0.32);
      const bulbGrad = ctx.createRadialGradient(cx, cy, 0, cx, cy, bulbRadius);
      bulbGrad.addColorStop(0,   `rgba(140,230,255,${bulbAlpha * 1.3})`);
      bulbGrad.addColorStop(0.4, `rgba(60,180,255,${bulbAlpha * 0.8})`);
      bulbGrad.addColorStop(1,   `rgba(0,100,200,0)`);
      ctx.save();
      ctx.beginPath(); ctx.arc(cx, cy, imgR * 0.78, 0, Math.PI * 2); ctx.clip();
      ctx.fillStyle = bulbGrad;
      ctx.fillRect(cx - imgR, cy - imgR, imgR * 2, imgR * 2);
      ctx.restore();
      // ── Electronic Shockwave — digital signal wave with sparks & glitch ──
      const phase = (t * 0.28) % 1;
      if(phase > 0.01){
        const waveR = phase * imgR * 1.6;
        const masterAlpha = Math.pow(1 - phase, 2.2) * 0.42;
        if(masterAlpha > 0.01){
          const crestWidth = 58 * (1 - phase * 0.3);
          const layers = 36;
          for(let l = 0; l < layers; l++){
            const offset = (l / (layers - 1) - 0.5) * crestWidth;
            const distFromCrest = Math.abs(l / (layers - 1) - 0.5) * 2;
            const layerAlpha = masterAlpha * Math.exp(-distFromCrest * distFromCrest * 3.0);
            const rr0 = waveR + offset;
            if(rr0 <= 0) continue;
            ctx.save();
            ctx.globalAlpha = layerAlpha;
            ctx.shadowColor = `rgba(0,210,255,${layerAlpha})`;
            ctx.shadowBlur = distFromCrest < 0.3 ? 22 * (1 - phase) : 8;
            const crestBlend = 1 - distFromCrest;
            const r2 = Math.floor(60 + crestBlend * 160 + phase * 60);
            const g2 = Math.floor(180 + crestBlend * 60 - phase * 40);
            ctx.strokeStyle = `rgba(${r2},${g2},255,1)`;
            ctx.lineWidth = distFromCrest < 0.25 ? 3 : 1.5;
            ctx.beginPath();
            const steps = 120;
            for(let s = 0; s <= steps; s++){
              const angle = (s / steps) * Math.PI * 2;
              // Electronic noise: sharp sawtooth + high-freq spikes instead of smooth sin
              const saw1 = ((angle * 4 + t * 3) % (Math.PI * 2) - Math.PI) / Math.PI;
              const saw2 = ((angle * 9 - t * 4) % (Math.PI * 2) - Math.PI) / Math.PI;
              const spike = Math.random() < 0.04 ? (Math.random() - 0.5) * 10 : 0;
              const noise =
                saw1 * 4 * (1 - phase) +
                saw2 * 2.5 * (1 - phase) +
                Math.sin(angle * 18 + t * 8) * 1.5 * (1 - phase) +
                spike;
              const rx = rr0 + noise;
              const x = cx + rx * Math.cos(angle);
              const y = cy + rx * Math.sin(angle);
              s === 0 ? ctx.moveTo(x, y) : ctx.lineTo(x, y);
            }
            ctx.closePath();
            ctx.stroke();
            ctx.restore();
          }
          // ── Electric sparks along the crest ──
          const sparkCount = 12;
          for(let sp = 0; sp < sparkCount; sp++){
            const angle = (sp / sparkCount) * Math.PI * 2 + t * 0.5;
            const saw1 = ((angle * 4 + t * 3) % (Math.PI * 2) - Math.PI) / Math.PI;
            const sparkR = waveR + saw1 * 4 * (1 - phase);
            const sx = cx + sparkR * Math.cos(angle);
            const sy = cy + sparkR * Math.sin(angle);
            const sparkAlpha = masterAlpha * (0.5 + 0.5 * Math.sin(t * 12 + sp * 1.7));
            if(sparkAlpha < 0.05) continue;
            ctx.save();
            ctx.globalAlpha = sparkAlpha;
            ctx.shadowColor = "#00ffff"; ctx.shadowBlur = 14;
            ctx.strokeStyle = "#aaffff"; ctx.lineWidth = 1.5;
            // small lightning fork
            const forkLen = 6 + Math.random() * 8;
            const forkAngle = angle + Math.PI / 2 + (Math.random() - 0.5) * 0.8;
            ctx.beginPath();
            ctx.moveTo(sx, sy);
            ctx.lineTo(
              sx + forkLen * Math.cos(forkAngle),
              sy + forkLen * Math.sin(forkAngle)
            );
            ctx.stroke();
            // spark dot
            ctx.beginPath(); ctx.arc(sx, sy, 2, 0, Math.PI * 2);
            ctx.fillStyle = "#ffffff"; ctx.fill();
            ctx.restore();
          }
          // ── Digital tick marks perpendicular to wave (signal indicator look) ──
          const tickCount = 32;
          for(let tk = 0; tk < tickCount; tk++){
            const angle = (tk / tickCount) * Math.PI * 2;
            const tickAlpha = masterAlpha * 0.6 * (0.4 + 0.6 * Math.abs(Math.sin(t * 6 + tk)));
            const tickR = waveR;
            ctx.save();
            ctx.globalAlpha = tickAlpha;
            ctx.strokeStyle = `rgba(0,255,220,0.9)`;
            ctx.lineWidth = 1;
            ctx.beginPath();
            ctx.moveTo(cx + (tickR - 6) * Math.cos(angle), cy + (tickR - 6) * Math.sin(angle));
            ctx.lineTo(cx + (tickR + 6) * Math.cos(angle), cy + (tickR + 6) * Math.sin(angle));
            ctx.stroke();
            ctx.restore();
          }
        }
      }
    };

    // ── Neural Network Background ──────────────────────────────────────────────────
    const drawBG = (t) => {
      // Deep dynamic gradient
      const vg=ctx.createRadialGradient(CX,CY,0,CX,CY,Math.max(W,H)*0.8);
      vg.addColorStop(0,"rgba(0, 10, 25, 0.55)"); 
      vg.addColorStop(1,"rgba(0, 2, 8, 0.65)");
      ctx.clearRect(0,0,W,H);
      ctx.fillStyle=vg; ctx.fillRect(0,0,W,H);

      // Simulation physics
      const particles = particlesRef.current;
      for (let i = 0; i < P_COUNT; i++) {
        const p = particles[i];
        p.x += p.vx; p.y += p.vy;
        
        // Soft boundaries
        if (p.x < -50) p.x = W + 50; if (p.x > W + 50) p.x = -50;
        if (p.y < -50) p.y = H + 50; if (p.y > H + 50) p.y = -50;
        
        // Subtle drift
        p.vx += (Math.random() - 0.5) * 0.02;
        p.vy += (Math.random() - 0.5) * 0.02;
        
        // Speed limits
        const speed = Math.sqrt(p.vx*p.vx + p.vy*p.vy);
        if (speed > 1.5) { p.vx = (p.vx/speed)*1.5; p.vy = (p.vy/speed)*1.5; }

        ctx.beginPath();
        ctx.arc(p.x, p.y, p.r, 0, Math.PI * 2);
        ctx.fillStyle = `rgba(0, 238, 255, ${p.glow})`;
        ctx.fill();

        for (let j = i + 1; j < P_COUNT; j++) {
          const p2 = particles[j];
          const dx = p.x - p2.x;
          const dy = p.y - p2.y;
          const dist = Math.sqrt(dx*dx + dy*dy);
          if (dist < 140) {
            ctx.beginPath();
            ctx.moveTo(p.x, p.y);
            ctx.lineTo(p2.x, p2.y);
            ctx.strokeStyle = `rgba(0, 238, 255, ${0.2 * (1 - dist/140)})`;
            ctx.lineWidth = 0.8;
            ctx.stroke();
          }
        }
      }


      
      // Corner accents
      [[0,0,1,1],[W,0,-1,1],[0,H,1,-1],[W,H,-1,-1]].forEach(([bx,by,dx,dy])=>{
        const L=40,T=5;
        ctx.save(); ctx.shadowColor=PC.CYAN; ctx.shadowBlur=10;
        ctx.strokeStyle="rgba(0, 238, 255, 0.6)"; ctx.lineWidth=2;
        ctx.beginPath(); ctx.moveTo(bx+dx*T,by+dy*T); ctx.lineTo(bx+dx*T,by+dy*(T+L)); ctx.stroke();
        ctx.beginPath(); ctx.moveTo(bx+dx*T,by+dy*T); ctx.lineTo(bx+dx*(T+L),by+dy*T); ctx.stroke();
        ctx.restore();
      });
    };

    // ── Top Bar ───────────────────────────────────────────────────────────
    const drawTop = (t,now,hs) => {
      const TH=56;
      const grad=ctx.createLinearGradient(0,0,0,TH);
      grad.addColorStop(0,"rgba(0,22,60,0.98)"); grad.addColorStop(1,"rgba(0,10,28,0.98)");
      ctx.fillStyle=grad; ctx.fillRect(0,0,W,TH);
      const bg=ctx.createLinearGradient(0,0,W,0);
      bg.addColorStop(0,"rgba(0,100,200,0)");
      bg.addColorStop(Math.abs(Math.sin(t*.6))*.3+.25,"rgba(0,230,255,0.85)");
      bg.addColorStop(Math.min(1,Math.abs(Math.sin(t*.6))*.3+.7),"rgba(130,60,255,0.6)");
      bg.addColorStop(1,"rgba(0,100,200,0)");
      ctx.strokeStyle=bg; ctx.lineWidth=1; ctx.beginPath(); ctx.moveTo(0,TH); ctx.lineTo(W,TH); ctx.stroke();
      // Left
      ctx.save(); ctx.shadowColor=PC.CYAN; ctx.shadowBlur=12;
      dt(20,20,"◈  RYAN AI",PC.CYAN,'bold 13px "Courier New"'); ctx.restore();

      // Center — RYAN OS title (moved from bottom, big font)
      ctx.save(); ctx.shadowColor=PC.CYAN; ctx.shadowBlur=18;
      glow(CX,22,"RYAN  OS  ·  REACTIVE  INTELLIGENCE",PC.CYAN,'bold 20px "Courier New"',"center",16);
      ctx.restore();
      const pulse=Math.floor(t*2)%2===0;
      dt(CX,46,`${pulse?"◉":"◎"}  ${Brain.providerName}  ·  KB: ${KB.getCount()}  ·  MEM: ${Memory.getAll().length}`,
        pulse?"#00cc77":PC.LABEL,'10px "Courier New"',"center");
      // Right
      const up=Math.floor(performance.now()/1000),hr=Math.floor(up/3600),mn=Math.floor((up%3600)/60),sc=up%60;
      dt(W-18,20,`UPTIME  ${hr.toString().padStart(2,"0")}:${mn.toString().padStart(2,"0")}:${sc.toString().padStart(2,"0")}`,
        PC.WHITE,'bold 12px "Courier New"',"right");
      dt(W-18,40,`CPU ${hs.cpu.toFixed(0)}%  ·  RAM ${hs.ram.toFixed(0)}%`,PC.LABEL,'10px "Courier New"',"right");
    };

    // ── Bottom Bar ─────────────────────────────────────────────────────────
    const drawBottom = (t,now,hs) => {
      const BB=H-48;
      const bg2=ctx.createLinearGradient(0,BB,0,H);
      bg2.addColorStop(0,"rgba(0,10,28,0.98)"); bg2.addColorStop(1,"rgba(0,22,60,0.98)");
      ctx.fillStyle=bg2; ctx.fillRect(0,BB,W,H-BB);
      const bg3=ctx.createLinearGradient(0,0,W,0);
      bg3.addColorStop(0,"rgba(0,100,200,0)"); bg3.addColorStop(.5,"rgba(0,210,255,0.55)"); bg3.addColorStop(1,"rgba(0,100,200,0)");
      ctx.strokeStyle=bg3; ctx.lineWidth=1; ctx.beginPath(); ctx.moveTo(0,BB); ctx.lineTo(W,BB); ctx.stroke();
      const dow=now.toLocaleDateString("en-IN",{weekday:"long"}).toUpperCase();
      const dm=now.toLocaleDateString("en-IN",{day:"2-digit",month:"short",year:"numeric"}).toUpperCase();
      dt(18,BB+18,`${dow}  ·  ${dm}`,PC.TEAL,'11px "Courier New"');
      dt(18,BB+36,`NET ↓${humanBytes(hs.net_rx)}/s  ↑${humanBytes(hs.net_tx)}/s  ·  PING ${hs.ping}ms`,PC.LABEL,'10px "Courier New"');
      dt(CX,BB+18,"TAP = CHAT  ·  DOUBLE-TAP = APPS  ·  ⚙ = SETTINGS",PC.DIMTEXT,'9px "Courier New"',"center");
      
      const ac=Math.floor(t*2)%2===0?"#00ee77":"#007744";
      dt(W-18,BB+18,"◉ SYSTEM ACTIVE",ac,'bold 11px "Courier New"',"right");
      dt(W-18,BB+36,`STT: ${hs.sttEnabled?"ON":"OFF"}  ·  IP: ${hs.ip}`,PC.LABEL,'10px "Courier New"',"right");
    };

    // ── Left Panel — System Stats ─────────────────────────────────────────
    const drawLeft = (t,now,hs) => {
      const LW=Math.min(200,W*.155),LX=0;
      const grad=ctx.createLinearGradient(0,0,LW,0);
      grad.addColorStop(0,"rgba(0,18,50,0.80)"); grad.addColorStop(1,"rgba(0,10,28,0.75)");
      ctx.fillStyle=grad; ctx.fillRect(LX,56,LW,H-56-48);
      ctx.strokeStyle=PC.BORDER; ctx.lineWidth=0.5;
      ctx.beginPath(); ctx.moveTo(LW,56); ctx.lineTo(LW,H-48); ctx.stroke();

      let y=62;

      // ── helper: premium card with gradient + glow accent bar ──
      const lCard=(cy,ch,accentCol)=>{
        const cg=ctx.createLinearGradient(LX,cy,LX+LW,cy+ch);
        cg.addColorStop(0,"rgba(0,8,24,0.97)"); cg.addColorStop(1,"rgba(0,15,38,0.97)");
        ctx.fillStyle=cg; ctx.fillRect(LX,cy,LW,ch);
        ctx.strokeStyle=accentCol+"44"; ctx.lineWidth=0.6; ctx.strokeRect(LX,cy,LW,ch);
        ctx.save(); ctx.shadowColor=accentCol; ctx.shadowBlur=7;
        ctx.fillStyle=accentCol; ctx.fillRect(LX,cy,3,ch);
        ctx.restore();
      };

      // ── HEADER ──────────────────────────────────────────────────────
      const hg=ctx.createLinearGradient(LX,y,LX+LW,y+26);
      hg.addColorStop(0,"rgba(0,20,50,0.98)"); hg.addColorStop(1,"rgba(0,40,80,0.98)");
      ctx.fillStyle=hg; ctx.fillRect(LX,y,LW,26);
      ctx.strokeStyle=PC.BORDER; ctx.lineWidth=0.6; ctx.strokeRect(LX,y,LW,26);
      const hAccL=ctx.createLinearGradient(LX,y,LX+LW,y);
      hAccL.addColorStop(0,PC.CYAN); hAccL.addColorStop(1,"rgba(0,238,255,0)");
      ctx.strokeStyle=hAccL; ctx.lineWidth=1;
      ctx.beginPath(); ctx.moveTo(LX,y); ctx.lineTo(LX+LW,y); ctx.stroke();
      ctx.save(); ctx.shadowColor=PC.CYAN; ctx.shadowBlur=6;
      dt(LX+9,y+13,"SYS MONITOR",PC.CYAN,'bold 9px "Courier New"');
      ctx.restore();
      const blink=Math.floor(t*2)%2===0;
      ctx.save();
      if(blink){ctx.shadowColor=PC.TEAL;ctx.shadowBlur=10;}
      ctx.beginPath(); ctx.arc(LX+LW-10,y+13,4,0,Math.PI*2);
      ctx.fillStyle=blink?PC.TEAL:"#004455"; ctx.fill(); ctx.restore();
      y+=28;

      // ── IP / PING ────────────────────────────────────────────────────
      ctx.fillStyle="rgba(0,10,28,0.9)"; ctx.fillRect(LX,y,LW,22);
      ctx.strokeStyle=PC.BORDER2; ctx.lineWidth=0.5; ctx.strokeRect(LX,y,LW,22);
      dt(LX+8,y+11,`IP ${hs.ip}`,PC.VALUE,'9px "Courier New"');
      const pingCol=hs.ping<30?PC.TEAL:hs.ping<80?PC.AMBER:PC.RED;
      dt(LX+LW-8,y+11,`${hs.ping}ms`,pingCol,'bold 9px "Courier New"',"right");
      y+=24;

      // ── CPU ──────────────────────────────────────────────────────────
      const cpuCol=hs.cpu<60?PC.GREEN:hs.cpu<85?PC.AMBER:PC.RED;
      lCard(y,94,cpuCol);
      dt(LX+9,y+13,"CPU  //  PROC",PC.LABEL,'bold 9px "Courier New"');
      const ccx=LX+38,ccy=y+58,cr=26;
      ctx.beginPath(); ctx.arc(ccx,ccy,cr,225*Math.PI/180,(225+270)*Math.PI/180);
      ctx.strokeStyle="rgba(0,20,50,1)"; ctx.lineWidth=6; ctx.stroke();
      const cpuEnd=225+Math.min(100,hs.cpu)/100*270;
      ctx.save(); ctx.shadowColor=cpuCol; ctx.shadowBlur=8;
      ctx.beginPath(); ctx.arc(ccx,ccy,cr,225*Math.PI/180,cpuEnd*Math.PI/180);
      ctx.strokeStyle=cpuCol; ctx.lineWidth=5; ctx.stroke(); ctx.restore();
      dt(ccx,ccy-6,"LOAD",PC.LABEL,'7px "Courier New"',"center");
      glow(ccx,ccy+8,`${hs.cpu.toFixed(0)}%`,cpuCol,'bold 15px "Courier New"',"center",8);
      ctx.save(); ctx.beginPath(); ctx.rect(LX+76,y+18,LW-82,54); ctx.clip();
      wave(LX+76,y+18,LW-82,52,hs.cpu_hist,cpuCol); ctx.restore();
      dt(LX+78,y+80,`${hs.cpu.toFixed(1)}%`,cpuCol,'9px "Courier New"');
      dt(LX+LW-6,y+80,`${navigator.hardwareConcurrency||"?"}c`,PC.LABEL,'9px "Courier New"',"right"); y+=96;

      // CPU bar segments
      const seg_n=16,seg_w=Math.floor((LW-8)/seg_n),active=Math.floor(hs.cpu/100*seg_n);
      ctx.fillStyle="rgba(0,8,22,0.9)"; ctx.fillRect(LX,y,LW,12);
      for(let si=0;si<seg_n;si++){ctx.fillStyle=si<active?cpuCol+"bb":"rgba(0,18,45,1)"; ctx.fillRect(LX+4+si*seg_w,y+2,seg_w-1,8);} y+=14;

      // ── RAM ──────────────────────────────────────────────────────────
      lCard(y,74,PC.CYAN);
      dt(LX+9,y+13,"RAM  //  MEM",PC.LABEL,'bold 9px "Courier New"');
      const ramMB=((navigator.deviceMemory||4)*1024*hs.ram/100)*1024*1024;
      dt(LX+9,y+30,`${humanBytes(ramMB)}`,PC.WHITE,'bold 14px "Courier New"');
      dt(LX+9,y+48,`of ${navigator.deviceMemory||4} GB`,PC.LABEL,'9px "Courier New"');
      bar(LX+8,y+61,LW-16,6,hs.ram,PC.CYAN);
      ctx.save(); ctx.shadowColor=PC.CYAN; ctx.shadowBlur=6;
      dt(LX+LW-6,y+30,`${hs.ram.toFixed(0)}%`,PC.CYAN,'bold 11px "Courier New"',"right"); ctx.restore();
      y+=76;

      // ── RAM history sparkline ────────────────────────────────────────
      ctx.fillStyle="rgba(0,6,20,0.9)"; ctx.fillRect(LX,y,LW,24);
      ctx.strokeStyle=PC.BORDER2; ctx.lineWidth=0.5; ctx.strokeRect(LX,y,LW,24);
      spark(LX+4,y+2,LW-8,20,hs.ram_hist,PC.CYAN); y+=26;

      // ── STORAGE ──────────────────────────────────────────────────────
      const diskCol=hs.disk<70?PC.GREEN:hs.disk<90?PC.AMBER:PC.RED;
      lCard(y,60,diskCol);
      dt(LX+9,y+13,"DRIVE  //  STORE",PC.LABEL,'bold 9px "Courier New"');
      dt(LX+9,y+32,`${hs.disk.toFixed(0)}%  USED`,PC.WHITE,'bold 13px "Courier New"');
      bar(LX+8,y+48,LW-16,6,hs.disk,diskCol); y+=62;

      // ── NETWORK I/O ──────────────────────────────────────────────────
      lCard(y,62,PC.TEAL);
      dt(LX+9,y+13,"NET  //  I/O",PC.LABEL,'bold 9px "Courier New"');
      ctx.save(); ctx.shadowColor=PC.CYAN; ctx.shadowBlur=4;
      dt(LX+9,y+32,`↓ ${humanBytes(hs.net_rx)}/s`,PC.CYAN,'bold 11px "Courier New"'); ctx.restore();
      ctx.save(); ctx.shadowColor=PC.TEAL; ctx.shadowBlur=4;
      dt(LX+9,y+50,`↑ ${humanBytes(hs.net_tx)}/s`,PC.TEAL,'bold 11px "Courier New"'); ctx.restore();
      y+=64;

      // ── BATTERY ─────────────────────────────────────────────────────
      if(hs.battery!==undefined){
        const batPct=Math.round(hs.battery.level*100);
        const batCol=batPct>60?PC.TEAL:batPct>20?PC.AMBER:PC.RED;
        lCard(y,66,batCol);
        dt(LX+9,y+13,"BATTERY",PC.LABEL,'bold 9px "Courier New"');
        ctx.save(); ctx.shadowColor=batCol; ctx.shadowBlur=6;
        dt(LX+LW-6,y+13,`${batPct}%`,batCol,'bold 10px "Courier New"',"right"); ctx.restore();
        // Battery body
        const bx=LX+8,by=y+26,bw=LW-20,bh=14;
        ctx.fillStyle="rgba(0,8,24,0.9)"; ctx.fillRect(bx,by,bw,bh);
        ctx.strokeStyle=batCol+"55"; ctx.lineWidth=1; ctx.strokeRect(bx,by,bw,bh);
        ctx.fillStyle=batCol+"44"; ctx.fillRect(bx+bw,by+4,4,bh-8);
        const fillW=Math.max(2,(batPct/100)*(bw-4));
        ctx.save(); ctx.shadowColor=batCol; ctx.shadowBlur=8;
        ctx.fillStyle=batCol; ctx.fillRect(bx+2,by+2,fillW,bh-4); ctx.restore();
        const chargeStr=hs.battery.charging?"⚡ CHARGING":"DISCHARGING";
        dt(LX+9,y+52,chargeStr,hs.battery.charging?PC.TEAL:PC.LABEL,'8px "Courier New"');
        const statusStr=batPct>60?"GOOD":batPct>20?"LOW":"CRITICAL";
        dt(LX+LW-6,y+52,statusStr,batCol,'bold 8px "Courier New"',"right");
        y+=68;
      }

      // ── CONNECTION ───────────────────────────────────────────────────
      const conn=navigator.connection||navigator.mozConnection||navigator.webkitConnection;
      if(conn){
        const netType=(conn.effectiveType||conn.type||"?").toUpperCase();
        const dl=conn.downlink||0;
        const connCol=netType.includes("4G")||netType.includes("WIFI")?PC.CYAN:PC.AMBER;
        lCard(y,62,connCol);
        dt(LX+9,y+13,"CONNECTION",PC.LABEL,'bold 9px "Courier New"');
        ctx.save(); ctx.shadowColor=connCol; ctx.shadowBlur=8;
        dt(LX+9,y+32,netType,connCol,'bold 16px "Courier New"'); ctx.restore();
        dt(LX+LW-6,y+32,`${dl}Mb/s`,PC.VALUE,'9px "Courier New"',"right");
        bar(LX+8,y+50,LW-16,5,Math.min(100,dl/20*100),connCol); y+=64;
      }

      // ── DEVICE SPECS ─────────────────────────────────────────────────
      lCard(y,64,PC.LABEL);
      dt(LX+9,y+13,"DEVICE SPECS",PC.LABEL,'bold 9px "Courier New"');
      dt(LX+9,y+30,`${screen.width}×${screen.height}`,PC.VALUE,'bold 11px "Courier New"');
      dt(LX+9,y+48,`${navigator.hardwareConcurrency||"?"}c · ${navigator.deviceMemory||4}GB`,PC.LABEL,'9px "Courier New"');
      dt(LX+LW-6,y+30,(navigator.language||"en").toUpperCase(),PC.TEAL,'bold 9px "Courier New"',"right");
      dt(LX+LW-6,y+48,navigator.platform?.slice(0,7)||"LINUX",PC.LABEL,'8px "Courier New"',"right"); y+=66;

      // ── SESSION UPTIME ───────────────────────────────────────────────
      {
        const upSec=Math.floor((Date.now()-sessionStartTime)/1000);
        const upH=Math.floor(upSec/3600),upM=Math.floor((upSec%3600)/60),upS=upSec%60;
        const upStr=`${upH.toString().padStart(2,"0")}:${upM.toString().padStart(2,"0")}:${upS.toString().padStart(2,"0")}`;
        lCard(y,50,PC.TEAL);
        dt(LX+9,y+13,"SESSION UPTIME",PC.LABEL,'bold 9px "Courier New"');
        ctx.save(); ctx.shadowColor=PC.TEAL; ctx.shadowBlur=8;
        dt(LX+LW/2,y+34,upStr,PC.TEAL,'bold 13px "Courier New"',"center"); ctx.restore();
        y+=52;
      }

      // ── PERFORMANCE SCORE ────────────────────────────────────────────
      {
        const score=Math.round(100-hs.cpu*0.5-hs.ram*0.3-Math.max(0,hs.ping-20)*0.2);
        const scoreCol=score>75?PC.TEAL:score>50?PC.AMBER:PC.RED;
        lCard(y,50,scoreCol);
        dt(LX+9,y+13,"PERF SCORE",PC.LABEL,'bold 9px "Courier New"');
        ctx.save(); ctx.shadowColor=scoreCol; ctx.shadowBlur=10;
        dt(LX+LW/2,y+34,`${Math.max(0,score)}`,scoreCol,'bold 18px "Courier New"',"center"); ctx.restore();
        dt(LX+LW-6,y+34,score>75?"OPTIMAL":score>50?"MODERATE":"STRESSED",scoreCol,'7px "Courier New"',"right");
        y+=52;
      }
    };

    // ── Right Panel — AI + Market ─────────────────────────────────────────
    const drawRight = (t,now,hs) => {
      const RW=Math.min(200,W*.155),RX=W-RW;
      const grad=ctx.createLinearGradient(RX,0,W,0);
      grad.addColorStop(0,"rgba(0,10,28,0.92)"); grad.addColorStop(1,"rgba(0,18,50,0.96)");
      ctx.fillStyle=grad; ctx.fillRect(RX,56,RW,H-56-48);
      ctx.strokeStyle=PC.BORDER; ctx.lineWidth=0.5;
      ctx.beginPath(); ctx.moveTo(RX,56); ctx.lineTo(RX,H-48); ctx.stroke();

      let y=62;
      // AI System header
      ctx.fillStyle="rgba(0,180,255,0.07)"; ctx.fillRect(RX,y,RW,22);
      ctx.strokeStyle=PC.BORDER2; ctx.lineWidth=0.5; ctx.strokeRect(RX,y,RW,22);
      dt(RX+RW-8,y+11,"RYAN AI  ·  SYSTEMS",PC.CYAN,'bold 9px "Courier New"',"right"); y+=24;

      // AI block
      ctx.fillStyle="rgba(0,14,38,0.9)"; ctx.fillRect(RX,y,RW,46);
      ctx.strokeStyle=PC.BORDER2; ctx.lineWidth=0.5; ctx.strokeRect(RX,y,RW,46);
      ctx.fillStyle=PC.CYAN; ctx.fillRect(RX,y,3,46);
      glow(RX+RW/2,y+16,`AI: ${Brain.providerName}`,PC.CYAN,'bold 11px "Courier New"',"center",7);
      dt(RX+RW/2,y+32,`KB: ${KB.getCount()}  ·  MEM: ${Memory.getAll().length}`,PC.LABEL,'9px "Courier New"',"center"); y+=48;

      // Weather
      if(hs.weather){
        const w=hs.weather;
        ctx.fillStyle="rgba(0,14,38,0.9)"; ctx.fillRect(RX,y,RW,46);
        ctx.strokeStyle=PC.BORDER2; ctx.lineWidth=0.5; ctx.strokeRect(RX,y,RW,46);
        ctx.fillStyle=PC.TEAL; ctx.fillRect(RX,y,3,46);
        glow(RX+RW/2,y+14,`${w.temp}°C  ·  ${w.desc.toUpperCase().slice(0,12)}`,PC.TEAL,'bold 12px "Courier New"',"center",6);
        dt(RX+8,y+32,`💧${w.humidity}%  💨${w.wind}km/h`,PC.LABEL,'9px "Courier New"');
        dt(RX+RW-8,y+32,w.city.slice(0,10).toUpperCase(),PC.LABEL,'9px "Courier New"',"right"); y+=48;
      }

      // ── Market Header ─────────────────────────────────────────────────
      const pulse2=Math.floor(t*2)%2===0;
      const mHdrH=28;
      const mHdrGrad=ctx.createLinearGradient(RX,y,RX+RW,y+mHdrH);
      mHdrGrad.addColorStop(0,"rgba(0,20,50,0.98)");
      mHdrGrad.addColorStop(1,"rgba(0,40,80,0.98)");
      ctx.fillStyle=mHdrGrad; ctx.fillRect(RX,y,RW,mHdrH);
      ctx.strokeStyle=PC.BORDER; ctx.lineWidth=0.6; ctx.strokeRect(RX,y,RW,mHdrH);
      // top accent line
      const hAccent=ctx.createLinearGradient(RX,y,RX+RW,y);
      hAccent.addColorStop(0,"rgba(0,238,255,0)");
      hAccent.addColorStop(0.5,PC.CYAN);
      hAccent.addColorStop(1,"rgba(0,238,255,0)");
      ctx.strokeStyle=hAccent; ctx.lineWidth=1;
      ctx.beginPath(); ctx.moveTo(RX,y); ctx.lineTo(RX+RW,y); ctx.stroke();
      ctx.save(); ctx.shadowColor=PC.CYAN; ctx.shadowBlur=8;
      dt(RX+10,y+mHdrH/2,`${pulse2?"◉":"◎"}  MARKET TERMINAL`,pulse2?PC.CYAN:"#006688",'bold 9px "Courier New"',"left");
      ctx.restore();
      dt(RX+RW-8,y+mHdrH/2,"TAP ▶",PC.LABEL,'8px "Courier New"',"right");
      y+=mHdrH+2;

      // ── Stock Cards ───────────────────────────────────────────────────
      StockEngine.getAll().forEach(stock=>{
        const eH=80;
        const isUp=stock.pct>=0;
        // Use cyan/teal for gains, red for losses — all holographic
        const col=isUp?PC.CYAN:PC.RED;
        const colDim=isUp?"rgba(0,238,255,0.12)":"rgba(255,42,85,0.12)";
        const colBorder=isUp?"rgba(0,238,255,0.25)":"rgba(255,42,85,0.25)";

        // Card background
        const cardGrad=ctx.createLinearGradient(RX,y,RX+RW,y+eH);
        cardGrad.addColorStop(0,"rgba(0,8,24,0.97)");
        cardGrad.addColorStop(1,"rgba(0,15,38,0.97)");
        ctx.fillStyle=cardGrad; ctx.fillRect(RX,y,RW,eH);
        ctx.strokeStyle=colBorder; ctx.lineWidth=0.6; ctx.strokeRect(RX,y,RW,eH);

        // Left accent bar with glow
        ctx.save();
        ctx.shadowColor=col; ctx.shadowBlur=8;
        ctx.fillStyle=col; ctx.fillRect(RX,y,3,eH);
        ctx.restore();

        // Subtle tinted fill on left
        ctx.fillStyle=colDim; ctx.fillRect(RX+3,y,RW*0.45,eH);

        // Stock name
        ctx.save(); ctx.shadowColor=PC.CYAN; ctx.shadowBlur=4;
        dt(RX+10,y+15,stock.name,PC.WHITE,'bold 11px "Courier New"');
        ctx.restore();

        // Source badge
        const liveCol=stock.source==="live"?PC.TEAL:"#446688";
        dt(RX+10,y+30,stock.source==="live"?"◉ LIVE":"◎ SIM",liveCol,'bold 8px "Courier New"');

        // Price — big and glowing
        ctx.save(); ctx.shadowColor=col; ctx.shadowBlur=10;
        dt(RX+RW-8,y+15,stock.last.toLocaleString("en-IN",{maximumFractionDigits:0}),col,'bold 14px "Courier New"',"right");
        ctx.restore();

        // Change %
        dt(RX+RW-8,y+30,`${isUp?"+":""}${stock.pct.toFixed(2)}%`,col,'bold 9px "Courier New"',"right");

        // Sparkline — taller, more visible
        spark(RX+6,y+40,RW-12,32,stock.prices,col);

        y+=eH+3;
      });

      // ── Footer ────────────────────────────────────────────────────────
      ctx.fillStyle="rgba(0,6,18,0.97)"; ctx.fillRect(RX,y,RW,26);
      ctx.strokeStyle=PC.BORDER; ctx.lineWidth=0.5; ctx.strokeRect(RX,y,RW,26);
      const fAccent=ctx.createLinearGradient(RX,y+26,RX+RW,y+26);
      fAccent.addColorStop(0,"rgba(0,238,255,0)");
      fAccent.addColorStop(0.5,PC.CYAN);
      fAccent.addColorStop(1,"rgba(0,238,255,0)");
      ctx.strokeStyle=fAccent; ctx.lineWidth=0.8;
      ctx.beginPath(); ctx.moveTo(RX,y+26); ctx.lineTo(RX+RW,y+26); ctx.stroke();
      ctx.save(); ctx.shadowColor=PC.CYAN; ctx.shadowBlur=5;
      glow(RX+RW/2,y+13,"▼ FULL MARKET VIEW",PC.LABEL,'bold 8px "Courier New"',"center",5);
      ctx.restore();
    };

    // ── Center ────────────────────────────────────────────────────────────
    const drawCenter = (t,now,hs) => {
      const LW=Math.min(200,W*.155),RW=Math.min(200,W*.155);
      const CR=Math.min(264,(W-LW-RW)*.66);
      drawReactor(CX,CY,CR,t);
      // Title


      // Clock
      glow(CX,CY+CR+36,
        now.toLocaleTimeString("en-IN",{hour12:false,hour:"2-digit",minute:"2-digit",second:"2-digit"}),
        PC.CYAN,'bold 30px "Courier New"',"center",20);
      glow(CX,CY+CR+68,
        now.toLocaleDateString("en-IN",{weekday:"long",year:"numeric",month:"long",day:"numeric"}).toUpperCase(),
        PC.TEAL,'11px "Courier New"',"center",6);
      if(hs.weather)
        dt(CX,CY+CR+88,`${hs.weather.city.toUpperCase()}  ·  ${hs.weather.temp}°C  ·  ${hs.weather.desc.toUpperCase()}`,
          PC.LABEL,'10px "Courier New"',"center");
      dt(CX,CY+CR+110,"[ TAP = CHAT   ·   DOUBLE-TAP = APPS   ·   ⚙ = SETTINGS ]",
        PC.DIMTEXT,'9px "Courier New"',"center");
      // Cardinal labels
      const lbls=[["AI","NEURAL",CX-CR-44,CY-28],["MEM","MEMORY",CX+CR+44,CY-28],["NET","NETWORK",CX,CY-CR-58],["SYS","SYSTEMS",CX,CY+CR+130]];
      lbls.forEach(([l2,l1,x,y2])=>{
        glow(x,y2,l2,PC.CYAN,'bold 10px "Courier New"',"center",6);
        dt(x,y2+14,l1,PC.LABEL,'8px "Courier New"',"center");
      });

    };

    const draw = (ts) => {
      if(ts-lastFrameRef.current<33){animRef.current=requestAnimationFrame(draw);return;}
      lastFrameRef.current=ts; tRef.current+=.033;
      const t=tRef.current,now=new Date(),hs=hudStateRef.current;
      ctx.clearRect(0,0,W,H);
      drawBG(t); drawCenter(t,now,hs); drawLeft(t,now,hs); drawRight(t,now,hs); drawTop(t,now,hs); drawBottom(t,now,hs);
      animRef.current=requestAnimationFrame(draw);
    };
    animRef.current=requestAnimationFrame(draw);
    return ()=>{cancelAnimationFrame(animRef.current); window.removeEventListener("resize",resize);};
  }, []);
  return canvasRef;
}

