// Deduplicate by tv key
const STOCK_DB_DEDUPED = (() => {
  const seen = new Set();
  return STOCK_DB.filter(s => { if(seen.has(s.tv)) return false; seen.add(s.tv); return true; });
})();

const SECTORS = [...new Set(STOCK_DB_DEDUPED.map(s => s.sector))].sort();

