const hydratePnl = (t) => {
  const rawPnl = t.type === "Long" ? (t.exit - t.entry) * t.qty : (t.entry - t.exit) * t.qty;
  return { ...t, pnl: rawPnl };
};
const SAMPLE = SAMPLE_TRADES.map(hydratePnl);

