/* ═══════════════════════════════════════════════════════════════
   STOCK SEARCH AUTOCOMPLETE COMPONENT
═══════════════════════════════════════════════════════════════ */
function StockSearch({ value, onChange, onSelect, placeholder = "Search NSE/BSE stocks...", style = {} }) {
  const [query, setQuery] = useState(value || "");
  const [open, setOpen] = useState(false);
  const [activeIdx, setActiveIdx] = useState(0);
  const [exFilter, setExFilter] = useState("ALL");
  const inputRef = useRef(null);
  const dropRef = useRef(null);

  const results = useMemo(() => {
    if (!query || query.length < 1) return [];
    const q = query.toLowerCase();
    return STOCK_DB_DEDUPED
      .filter(s => {
        if (exFilter !== "ALL" && s.exchange !== exFilter) return false;
        return s.sym.toLowerCase().includes(q) || s.name.toLowerCase().includes(q) || s.sector.toLowerCase().includes(q);
      })
      .slice(0, 10);
  }, [query, exFilter]);

  useEffect(() => {
    const handler = (e) => {
      if (!dropRef.current?.contains(e.target) && !inputRef.current?.contains(e.target)) {
        setOpen(false);
      }
    };
    document.addEventListener("mousedown", handler);
    return () => document.removeEventListener("mousedown", handler);
  }, []);

  const handleKey = (e) => {
    if (!open) { if (e.key === "ArrowDown") { setOpen(true); return; } }
    if (e.key === "ArrowDown") setActiveIdx(i => Math.min(i + 1, results.length - 1));
    else if (e.key === "ArrowUp") setActiveIdx(i => Math.max(i - 1, 0));
    else if (e.key === "Enter" && results[activeIdx]) { pick(results[activeIdx]); }
    else if (e.key === "Escape") setOpen(false);
  };

  const pick = (stock) => {
    setQuery(stock.sym);
    setOpen(false);
    onChange && onChange(stock.sym);
    onSelect && onSelect(stock);
  };

  const SECTOR_COLORS = {
    Index:"#00D4FF", Banking:"#4DA8DA", IT:"#8B5CF6", Energy:"#F97316",
    Pharma:"#0ECC6D", Auto:"#D4A843", FMCG:"#F04060", Finance:"#34d399",
    Power:"#60a5fa", Metals:"#fb923c", Telecom:"#a78bfa", Chemicals:"#ec4899",
    Realty:"#14b8a6", Healthcare:"#f59e0b", Default:"#8a8898"
  };
  const sc = (sector) => SECTOR_COLORS[sector] || SECTOR_COLORS.Default;

  return (
    <div style={{ position: "relative", ...style }}>
      {/* Exchange filter pills */}
      <div style={{ display: "flex", gap: 5, marginBottom: 6 }}>
        {["ALL", "NSE", "BSE"].map(ex => (
          <button key={ex} onClick={() => setExFilter(ex)} style={{
            padding: "3px 10px", borderRadius: 6, border: "none", cursor: "pointer",
            fontFamily: "var(--mono)", fontSize: 10, fontWeight: 700, letterSpacing: .5,
            background: exFilter === ex
              ? (ex === "BSE" ? "rgba(212,168,67,0.25)" : "rgba(0,212,255,0.18)")
              : "rgba(255,255,255,0.05)",
            color: exFilter === ex
              ? (ex === "BSE" ? "var(--gold)" : "var(--cyan)")
              : "var(--text-dim)",
            transition: "all .15s",
          }}>{ex}</button>
        ))}
      </div>
      <div style={{ position: "relative" }}>
        <input
          ref={inputRef}
          type="text"
          placeholder={placeholder}
          value={query}
          onChange={e => { setQuery(e.target.value); setOpen(true); setActiveIdx(0); onChange && onChange(e.target.value); }}
          onFocus={() => setOpen(true)}
          onKeyDown={handleKey}
          style={{ paddingLeft: "36px !important" }}
        />
        {/* Search icon */}
        <span style={{ position: "absolute", left: 12, top: "50%", transform: "translateY(-50%)", color: "var(--text-dim)", fontSize: 13, pointerEvents: "none" }}>⌕</span>
        {query && (
          <span onClick={() => { setQuery(""); onChange && onChange(""); }} style={{
            position: "absolute", right: 10, top: "50%", transform: "translateY(-50%)",
            color: "var(--text-dim)", cursor: "pointer", fontSize: 13, padding: "2px 4px",
          }}>✕</span>
        )}
      </div>
      {open && results.length > 0 && (
        <div className="stock-dropdown" ref={dropRef}>
          {results.map((stock, i) => (
            <div
              key={stock.tv}
              className={`stock-item${i === activeIdx ? " active" : ""}`}
              onMouseEnter={() => setActiveIdx(i)}
              onClick={() => pick(stock)}
            >
              <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
                <div style={{
                  width: 32, height: 24, borderRadius: 5, display: "flex", alignItems: "center", justifyContent: "center",
                  background: `${sc(stock.sector)}18`, border: `1px solid ${sc(stock.sector)}30`,
                  fontFamily: "var(--mono)", fontSize: 8, fontWeight: 700, color: sc(stock.sector), letterSpacing: .5,
                }}>{stock.exchange}</div>
                <div>
                  <div style={{ fontFamily: "var(--mono)", fontSize: 12, fontWeight: 600, color: "var(--text)" }}>{stock.sym}</div>
                  <div style={{ fontFamily: "var(--sans)", fontSize: 10, color: "var(--text-dim)", marginTop: 1 }}>{stock.name}</div>
                </div>
              </div>
              <div style={{
                fontFamily: "var(--sans)", fontSize: 9, color: sc(stock.sector),
                background: `${sc(stock.sector)}14`, border: `1px solid ${sc(stock.sector)}25`,
                padding: "2px 7px", borderRadius: 4, letterSpacing: .3,
              }}>{stock.sector}</div>
            </div>
          ))}
          <div style={{ padding: "8px 14px", fontFamily: "var(--mono)", fontSize: 10, color: "var(--text-dim)", borderTop: "1px solid var(--border)" }}>
            {STOCK_DB_DEDUPED.length}+ NSE/BSE stocks · ↑↓ Navigate · Enter to select
          </div>
        </div>
      )}
    </div>
  );
}

/* ═══════════════════════════════════════════════════════════════
   REUSABLE COMPONENTS
═══════════════════════════════════════════════════════════════ */
function Badge({ children, color, size = "sm" }) {
  const c = TAG_COLORS[children] || color || "var(--text-dim)";
  return (
    <span style={{
      background: c + "1a", color: c, border: `1px solid ${c}35`,
      borderRadius: 6, padding: size === "lg" ? "4px 12px" : "2px 8px",
      fontSize: size === "lg" ? 12 : 10, fontFamily: "var(--sans)",
      fontWeight: 600, letterSpacing: .4, display: "inline-block", whiteSpace: "nowrap",
    }}>{children}</span>
  );
}

function Spinner() {
  return <div className="spin" style={{ width: 15, height: 15, border: "2px solid rgba(255,255,255,0.1)", borderTop: "2px solid var(--cyan)", borderRadius: "50%", flexShrink: 0 }} />;
}

function Divider({ label }) {
  return (
    <div style={{ display: "flex", alignItems: "center", gap: 12, margin: "6px 0" }}>
      <div style={{ flex: 1, height: "1px", background: "var(--border)" }} />
      {label && <span style={{ fontFamily: "var(--mono)", fontSize: 10, color: "var(--text-dim)", letterSpacing: 2 }}>{label}</span>}
      <div style={{ flex: 1, height: "1px", background: "var(--border)" }} />
    </div>
  );
}

function StatCard({ label, value, sub, color = "var(--gold)", icon, delta, shimmer, delay = 0 }) {
  return (
    <div className="glass-card fade-up" style={{
      borderTop: `2px solid ${color}`, position: "relative", overflow: "hidden",
      animationDelay: `${delay}s`, cursor: "default", transition: "transform .2s, box-shadow .2s",
    }}
      onMouseEnter={e => { e.currentTarget.style.transform = "translateY(-3px)"; e.currentTarget.style.boxShadow = `0 12px 40px rgba(0,0,0,0.55), 0 0 0 1px ${color}25`; }}
      onMouseLeave={e => { e.currentTarget.style.transform = ""; e.currentTarget.style.boxShadow = ""; }}
    >
      <div style={{ position: "absolute", top: -40, right: -40, width: 110, height: 110, borderRadius: "50%", background: color + "0c", filter: "blur(35px)", pointerEvents: "none" }} />
      <div style={{ fontFamily: "var(--gothic)", fontSize: 8.5, letterSpacing: 2.5, color: "var(--text-dim)", textTransform: "uppercase", marginBottom: 12 }}>{label}</div>
      <div style={{
        fontFamily: "var(--mono)", fontSize: 26, fontWeight: 700, color, lineHeight: 1, letterSpacing: -.5,
        ...(shimmer ? { background: `linear-gradient(90deg, ${color} 0%, ${color}cc 40%, ${color} 60%)`, backgroundSize: "200% auto", WebkitBackgroundClip: "text", WebkitTextFillColor: "transparent", backgroundClip: "text", animation: "shimmer 3.5s linear infinite" } : {})
      }}>{value}</div>
      {sub && <div style={{ fontFamily: "var(--mono)", fontSize: 10.5, color: "var(--text-dim)", marginTop: 9, letterSpacing: -.1 }}>{sub}</div>}
      {delta !== undefined && (
        <div style={{
          display: "inline-flex", alignItems: "center", gap: 4, marginTop: 9, padding: "3px 10px", borderRadius: 7,
          background: delta >= 0 ? "var(--green-dim)" : "var(--red-dim)",
          fontFamily: "var(--mono)", fontSize: 11, color: delta >= 0 ? "var(--green)" : "var(--red)", fontWeight: 600,
        }}>{delta >= 0 ? "▲" : "▼"} {Math.abs(delta).toFixed(1)}%</div>
      )}
      {icon && <div style={{ position: "absolute", right: 18, top: 18, fontSize: 24, opacity: .08, pointerEvents: "none" }}>{icon}</div>}
    </div>
  );
}

const PremiumTooltip = ({ active, payload, label }) => {
  if (!active || !payload?.length) return null;
  return (
    <div style={{ background: "rgba(6,6,18,0.97)", border: "1px solid rgba(0,212,255,0.2)", borderRadius: 10, padding: "10px 14px", fontFamily: "var(--mono)", fontSize: 11, backdropFilter: "blur(20px)", boxShadow: "0 8px 32px rgba(0,0,0,0.5)" }}>
      <div style={{ color: "var(--text-dim)", marginBottom: 6, fontSize: 10, letterSpacing: .5 }}>{label}</div>
      {payload.map((p, i) => (
        <div key={i} style={{ color: p.value >= 0 ? "var(--green)" : "var(--red)", fontWeight: 600 }}>
          {p.name}: <span style={{ color: p.value >= 0 ? "var(--green)" : "var(--red)" }}>{fmt(p.value)}</span>
        </div>
      ))}
    </div>
  );
};

function StreakBadge({ trades }) {
  const streak = useMemo(() => {
    if (!trades.length) return { count: 0, type: null };
    const sorted = [...trades].sort((a, b) => b.date.localeCompare(a.date));
    const first = sorted[0].result;
    if (first === "BE") return { count: 0, type: null };
    let count = 0;
    for (const t of sorted) { if (t.result === first) count++; else break; }
    return { count, type: first };
  }, [trades]);
  if (!streak.type || streak.count < 2) return null;
  const isWin = streak.type === "Win";
  return (
    <div style={{ display: "flex", alignItems: "center", gap: 6, padding: "5px 12px", borderRadius: 20, background: isWin ? "rgba(14,204,109,0.08)" : "rgba(240,64,96,0.08)", border: `1px solid ${isWin ? "rgba(14,204,109,0.25)" : "rgba(240,64,96,0.25)"}` }}>
      <span style={{ fontSize: 14 }}>{isWin ? "🔥" : "❄️"}</span>
      <span style={{ fontFamily: "var(--mono)", fontSize: 12, fontWeight: 700, color: isWin ? "var(--green)" : "var(--red)", animation: isWin ? "greenPulse 2s ease infinite" : "none" }}>{streak.count} {streak.type} streak</span>
    </div>
  );
}

/* ═══════════════════════════════════════════════════════════════
   FINNHUB ENGINE — Central API client (zero TradingView)
═══════════════════════════════════════════════════════════════ */
const FH = {
  BASE: "https://finnhub.io/api/v1",
  async get(path, key) {
    try {
      const r = await fetch(`${this.BASE}${path}&token=${key}`, { signal: AbortSignal.timeout(9000) });
      if (!r.ok) return null;
      return await r.json();
    } catch { return null; }
  },
  async quote(sym, key) {
    const d = await this.get(`/quote?symbol=${encodeURIComponent(sym)}`, key);
    return d?.c > 0 ? d : null;
  },
  async candle(sym, res, from, to, key) {
    return await this.get(`/stock/candle?symbol=${encodeURIComponent(sym)}&resolution=${res}&from=${from}&to=${to}`, key);
  },
  async news(key) {
    return await this.get(`/news?category=general&minId=0`, key);
  },
  async earnings(from, to, key) {
    return await this.get(`/calendar/earnings?from=${from}&to=${to}`, key);
  },
  async ipo(from, to, key) {
    return await this.get(`/calendar/ipo?from=${from}&to=${to}`, key);
  },
  async search(q, key) {
    return await this.get(`/search?q=${encodeURIComponent(q)}`, key);
  },
  async metrics(sym, key) {
    return await this.get(`/stock/metric?symbol=${encodeURIComponent(sym)}&metric=all`, key);
  },
  async peers(sym, key) {
    return await this.get(`/stock/peers?symbol=${encodeURIComponent(sym)}`, key);
  },
};

/* ═══════════════════════════════════════════════════════════════
   TICKER TAPE — Finnhub live prices (no TradingView)
═══════════════════════════════════════════════════════════════ */
const TAPE_SYMBOLS = [
  { sym:"AAPL",             label:"AAPL" },
  { sym:"MSFT",             label:"MSFT" },
  { sym:"GOOGL",            label:"GOOGL" },
  { sym:"NVDA",             label:"NVDA" },
  { sym:"TSLA",             label:"TSLA" },
  { sym:"AMZN",             label:"AMZN" },
  { sym:"META",             label:"META" },
  { sym:"BINANCE:BTCUSDT",  label:"BTC/USDT" },
  { sym:"BINANCE:ETHUSDT",  label:"ETH/USDT" },
  { sym:"OANDA:USD_INR",    label:"USD/INR" },
  { sym:"NSE:RELIANCE",     label:"RELIANCE" },
  { sym:"NSE:TCS",          label:"TCS" },
  { sym:"NSE:HDFCBANK",     label:"HDFC BANK" },
  { sym:"NSE:INFY",         label:"INFOSYS" },
  { sym:"NSE:SBIN",         label:"SBI" },
  { sym:"NSE:ICICIBANK",    label:"ICICI" },
  { sym:"NSE:WIPRO",        label:"WIPRO" },
];

function FinnhubTickerTape({ apiKey }) {
  const [tickers, setTickers] = useState([]);
  const [loaded, setLoaded] = useState(false);

  useEffect(() => {
    if (!apiKey) { setLoaded(true); return; }
    let cancelled = false;
    (async () => {
      const results = [];
      for (const s of TAPE_SYMBOLS) {
        const q = await FH.quote(s.sym, apiKey);
        if (!cancelled && q) results.push({ ...s, c: q.c, dp: q.dp, d: q.d });
        if (!cancelled && results.length === 1) setTickers([...results]); // show first result fast
      }
      if (!cancelled) { setTickers(results); setLoaded(true); }
    })();
    return () => { cancelled = true; };
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [apiKey]);

  const items = tickers.length ? [...tickers, ...tickers] : [];

  return (
    <div style={{ borderBottom: "1px solid rgba(0,212,255,0.12)", background: "rgba(0,0,10,0.6)", height: 38, overflow: "hidden", display: "flex", alignItems: "center" }}>
      {!apiKey ? (
        <div style={{ width: "100%", display: "flex", alignItems: "center", gap: 8, padding: "0 16px" }}>
          <span style={{ fontFamily: "var(--mono)", fontSize: 9, color: "rgba(0,212,255,0.3)", letterSpacing: 2 }}>⚡ FINNHUB TICKER — ADD API KEY IN SETTINGS TO SEE LIVE PRICES</span>
        </div>
      ) : !loaded ? (
        <div style={{ padding: "0 16px", fontFamily: "var(--mono)", fontSize: 9, color: "rgba(0,212,255,0.4)", letterSpacing: 2 }}>FETCHING LIVE PRICES...</div>
      ) : (
        <div style={{ display: "flex", gap: 0, animation: "tickerScroll 40s linear infinite", whiteSpace: "nowrap", willChange: "transform" }}>
          {items.map((t, i) => {
            const up = t.dp >= 0;
            return (
              <span key={i} style={{ display: "inline-flex", alignItems: "center", gap: 6, padding: "0 20px", borderRight: "1px solid rgba(0,212,255,0.06)" }}>
                <span style={{ fontFamily: "var(--gothic)", fontSize: 9.5, color: "rgba(0,212,255,0.5)", letterSpacing: 1.5 }}>{t.label}</span>
                <span style={{ fontFamily: "var(--mono)", fontSize: 10.5, fontWeight: 700, color: up ? "#0ECC6D" : "#F04060" }}>{t.c?.toLocaleString("en-IN", { maximumFractionDigits: 2 })}</span>
                <span style={{ fontFamily: "var(--mono)", fontSize: 9, color: up ? "#0ECC6D" : "#F04060", opacity: .8 }}>{up ? "▲" : "▼"}{Math.abs(t.dp).toFixed(2)}%</span>
              </span>
            );
          })}
        </div>
      )}
      <style>{`@keyframes tickerScroll { 0%{transform:translateX(0)} 100%{transform:translateX(-50%)} }`}</style>
    </div>
  );
}

/* ═══════════════════════════════════════════════════════════════
   CANDLESTICK CHART — Pure SVG, zero TradingView
═══════════════════════════════════════════════════════════════ */
function CandlestickSVG({ data, width = 900, height = 320 }) {
  if (!data?.length) return null;
  const PAD = { top: 12, bottom: 28, left: 58, right: 14 };
  const W = width - PAD.left - PAD.right;
  const H = height - PAD.top - PAD.bottom;

  const prices = data.flatMap(d => [d.h, d.l]);
  const rawMin = Math.min(...prices), rawMax = Math.max(...prices);
  const pad = (rawMax - rawMin) * 0.05;
  const minP = rawMin - pad, maxP = rawMax + pad;
  const range = maxP - minP || 1;

  const toY = p => PAD.top + H - ((p - minP) / range) * H;
  const step = W / data.length;
  const candleW = Math.max(2, Math.min(12, step - 2));

  // Y axis labels
  const yTicks = 5;
  const yLabels = Array.from({ length: yTicks + 1 }, (_, i) => minP + (range * i) / yTicks);

  // SMA 20
  const sma20 = data.map((_, i) => {
    if (i < 19) return null;
    const slice = data.slice(i - 19, i + 1);
    return slice.reduce((s, d) => s + d.c, 0) / 20;
  });

  return (
    <svg viewBox={`0 0 ${width} ${height}`} width="100%" style={{ display: "block" }}>
      {/* Grid lines */}
      {yLabels.map((v, i) => (
        <g key={i}>
          <line x1={PAD.left} y1={toY(v)} x2={PAD.left + W} y2={toY(v)} stroke="rgba(255,255,255,0.04)" strokeWidth={1} />
          <text x={PAD.left - 6} y={toY(v) + 4} textAnchor="end" fontSize={8} fill="rgba(255,255,255,0.3)" fontFamily="monospace">
            {v >= 1000 ? (v / 1000).toFixed(1) + "k" : v.toFixed(v >= 100 ? 0 : 2)}
          </text>
        </g>
      ))}
      {/* X axis labels */}
      {data.map((d, i) => i % Math.ceil(data.length / 8) === 0 && (
        <text key={i} x={PAD.left + i * step + step / 2} y={height - 6} textAnchor="middle" fontSize={8} fill="rgba(255,255,255,0.3)" fontFamily="monospace">{d.date}</text>
      ))}
      {/* SMA 20 line */}
      <polyline
        fill="none" stroke="rgba(255,200,0,0.55)" strokeWidth={1.2} strokeDasharray="3 2"
        points={sma20.map((v, i) => v != null ? `${PAD.left + i * step + step / 2},${toY(v)}` : null).filter(Boolean).join(" ")}
      />
      {/* Candles */}
      {data.map((d, i) => {
        const x = PAD.left + i * step + step / 2;
        const isUp = d.c >= d.o;
        const col = isUp ? "#0ECC6D" : "#F04060";
        const bodyTop = toY(Math.max(d.o, d.c));
        const bodyBot = toY(Math.min(d.o, d.c));
        const bodyH = Math.max(1, bodyBot - bodyTop);
        return (
          <g key={i}>
            {/* Wick */}
            <line x1={x} y1={toY(d.h)} x2={x} y2={toY(d.l)} stroke={col} strokeWidth={1} />
            {/* Body */}
            <rect x={x - candleW / 2} y={bodyTop} width={candleW} height={bodyH}
              fill={isUp ? col : col} fillOpacity={isUp ? 0.85 : 1}
              stroke={col} strokeWidth={0.5}
            />
          </g>
        );
      })}
      {/* Border */}
      <rect x={PAD.left} y={PAD.top} width={W} height={H} fill="none" stroke="rgba(0,212,255,0.1)" strokeWidth={1} />
    </svg>
  );
}

/* Volume bar chart below candlestick */
function VolumeSVG({ data, width = 900, height = 60 }) {
  if (!data?.length) return null;
  const PAD = { top: 4, bottom: 16, left: 58, right: 14 };
  const W = width - PAD.left - PAD.right;
  const H = height - PAD.top - PAD.bottom;
  const maxVol = Math.max(...data.map(d => d.v || 0)) || 1;
  const step = W / data.length;
  const barW = Math.max(1, step - 1.5);

  return (
    <svg viewBox={`0 0 ${width} ${height}`} width="100%" style={{ display: "block" }}>
      <text x={PAD.left - 6} y={PAD.top + 8} textAnchor="end" fontSize={7} fill="rgba(255,255,255,0.2)" fontFamily="monospace">VOL</text>
      {data.map((d, i) => {
        const barH = Math.max(1, ((d.v || 0) / maxVol) * H);
        const isUp = d.c >= d.o;
        return (
          <rect key={i}
            x={PAD.left + i * step + (step - barW) / 2}
            y={PAD.top + H - barH} width={barW} height={barH}
            fill={isUp ? "rgba(14,204,109,0.4)" : "rgba(240,64,96,0.4)"}
          />
        );
      })}
    </svg>
  );
}

/* ═══════════════════════════════════════════════════════════════
   YAHOO FINANCE CHART — free, no API key, full NSE/BSE/US coverage
   Used automatically for Indian stocks to avoid TradingView's
   "This symbol is only available on TradingView" popup
═══════════════════════════════════════════════════════════════ */
function YahooChart({ symbol, interval = "D" }) {
  const [candles, setCandles] = useState(null);
  const [quote,   setQuote]   = useState(null);
  const [loading, setLoading] = useState(false);
  const [error,   setError]   = useState("");

  // Finnhub symbol format → Yahoo Finance ticker
  const toYahoo = (s) => {
    if (s.startsWith("NSE:"))     return s.replace("NSE:", "") + ".NS";
    if (s.startsWith("BSE:"))     return s.replace("BSE:", "") + ".BO";
    if (s.startsWith("BINANCE:")) return s.replace("BINANCE:", "").replace("USDT", "-USD").replace("BTC", "BTC");
    if (s.startsWith("OANDA:"))   return s.replace("OANDA:", "").replace("_", "") + "=X";
    return s; // US stocks work as-is (AAPL, MSFT etc.)
  };

  // Finnhub resolution → [Yahoo interval, Yahoo range]
  const toYahooParams = (r) => ({
    "1":   ["1m",  "1d"],
    "5":   ["5m",  "5d"],
    "15":  ["15m", "5d"],
    "30":  ["30m", "10d"],
    "60":  ["60m", "1mo"],
    "240": ["60m", "3mo"],
    "D":   ["1d",  "6mo"],
    "W":   ["1wk", "2y"],
  }[r] || ["1d", "6mo"]);

  useEffect(() => {
    const ticker = toYahoo(symbol);
    const [yInt, yRange] = toYahooParams(interval);
    setLoading(true); setError(""); setCandles(null); setQuote(null);

    const yUrl = `https://query1.finance.yahoo.com/v8/finance/chart/${ticker}?interval=${yInt}&range=${yRange}&includePrePost=false`;
    // allorigins proxy bypasses Yahoo CORS restriction
    const proxy = `https://api.allorigins.win/get?url=${encodeURIComponent(yUrl)}`;

    fetch(proxy)
      .then(r => r.json())
      .then(raw => {
        let parsed;
        try { parsed = JSON.parse(raw.contents); } catch { throw new Error("Parse error"); }
        const result = parsed?.chart?.result?.[0];
        if (!result) throw new Error("No chart data returned");

        const { timestamp, indicators, meta } = result;
        const ohlcv = indicators.quote[0];

        const data = timestamp
          .map((ts, i) => ({
            date: new Date(ts * 1000).toLocaleDateString("en-IN", { month: "short", day: "numeric" }),
            o: ohlcv.open?.[i],
            h: ohlcv.high?.[i],
            l: ohlcv.low?.[i],
            c: ohlcv.close?.[i],
            v: ohlcv.volume?.[i] || 0,
          }))
          .filter(d => d.c != null && d.o != null)
          .slice(-120);

        if (!data.length) throw new Error("No valid candles in response");

        setCandles(data);
        const prev = meta.chartPreviousClose || meta.previousClose || data[data.length - 2]?.c || data[data.length - 1].c;
        const curr = meta.regularMarketPrice || data[data.length - 1].c;
        setQuote({
          c: curr,
          h: meta.regularMarketDayHigh,
          l: meta.regularMarketDayLow,
          o: meta.regularMarketOpen,
          dp: ((curr - prev) / prev * 100),
          d:  curr - prev,
        });
        setLoading(false);
      })
      .catch(e => { setError("Yahoo Finance fetch failed: " + e.message); setLoading(false); });
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [symbol, interval]);

  const fmtP = (n) => n == null ? "--" : n >= 1000 ? n.toLocaleString("en-IN", { maximumFractionDigits: 2 }) : n.toFixed(2);
  const isUp = quote ? quote.dp >= 0 : true;
  const last = candles?.[candles.length - 1];
  const first = candles?.[0];
  const periodReturn = (last && first) ? ((last.c - first.c) / first.c * 100).toFixed(2) : null;

  return (
    <div className="glass-card" style={{ padding: "16px 16px 10px" }}>
      {/* Header row */}
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 12, flexWrap: "wrap", gap: 8 }}>
        <div style={{ display: "flex", gap: 12, alignItems: "center", flexWrap: "wrap" }}>
          <div style={{ fontFamily: "var(--mono)", fontSize: 13, color: "var(--cyan)", fontWeight: 700 }}>{symbol}</div>
          {quote && (
            <>
              <div style={{ fontFamily: "var(--mono)", fontSize: 22, fontWeight: 700, color: isUp ? "var(--green)" : "var(--red)", lineHeight: 1 }}>
                {fmtP(quote.c)}
              </div>
              <div style={{ fontFamily: "var(--mono)", fontSize: 12, color: isUp ? "var(--green)" : "var(--red)" }}>
                {isUp ? "▲" : "▼"}{Math.abs(quote.dp).toFixed(2)}% &nbsp;({quote.d >= 0 ? "+" : ""}{fmtP(quote.d)})
              </div>
            </>
          )}
        </div>
        <div style={{ display: "flex", alignItems: "center", gap: 6 }}>
          <div style={{ width: 7, height: 7, borderRadius: "50%", background: "#0ECC6D", boxShadow: "0 0 6px #0ECC6D", animation: "pulse 2s infinite" }} />
          <span style={{ fontFamily: "var(--gothic)", fontSize: 9, color: "#0ECC6D", letterSpacing: 2 }}>YAHOO FINANCE · LIVE · NO API KEY</span>
        </div>
      </div>

      {/* OHLC mini stats */}
      {quote && (
        <div style={{ display: "flex", gap: 10, marginBottom: 10, flexWrap: "wrap" }}>
          {[["Open", quote.o], ["High", quote.h], ["Low", quote.l]].map(([l, v]) => (
            <div key={l} style={{ fontFamily: "var(--mono)", fontSize: 10, color: "var(--text-dim)" }}>
              {l}: <span style={{ color: "var(--text)" }}>{fmtP(v)}</span>
            </div>
          ))}
        </div>
      )}

      {/* Loading */}
      {loading && (
        <div style={{ height: 380, display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", gap: 16 }}>
          <div className="spin" style={{ width: 36, height: 36, border: "3px solid rgba(14,204,109,0.1)", borderTopColor: "#0ECC6D", borderRadius: "50%" }} />
          <div style={{ fontFamily: "var(--gothic)", fontSize: 11, color: "#0ECC6D", letterSpacing: 2 }}>LOADING FROM YAHOO FINANCE...</div>
        </div>
      )}

      {/* Error */}
      {error && !loading && (
        <div style={{ padding: "30px 20px", textAlign: "center", color: "var(--red)", fontFamily: "var(--mono)", fontSize: 12 }}>⚠ {error}</div>
      )}

      {/* Chart */}
      {candles && !loading && (
        <>
          <CandlestickSVG data={candles} width={1100} height={340} />
          <VolumeSVG data={candles} width={1100} height={56} />
          <div style={{ display: "flex", gap: 10, marginTop: 10, flexWrap: "wrap" }}>
            {(() => {
              const l = candles[candles.length - 1];
              return [["Open",l.o],["High",l.h],["Low",l.l],["Close",l.c],["Volume",l.v ? (l.v/1e6).toFixed(2)+"M":"--"]].map(([lbl,v])=>(
                <div key={lbl} style={{ background:"rgba(255,255,255,0.03)",borderRadius:7,padding:"6px 12px",textAlign:"center" }}>
                  <div style={{ fontFamily:"var(--gothic)",fontSize:8,color:"var(--text-dim)",letterSpacing:1.5 }}>{lbl}</div>
                  <div style={{ fontFamily:"var(--mono)",fontSize:11,color:"var(--text)",fontWeight:600,marginTop:3 }}>{typeof v==="number"?fmtP(v):v}</div>
                </div>
              ));
            })()}
            {periodReturn && (
              <div style={{ background:"rgba(255,255,255,0.03)",borderRadius:7,padding:"6px 12px",textAlign:"center" }}>
                <div style={{ fontFamily:"var(--gothic)",fontSize:8,color:"var(--text-dim)",letterSpacing:1.5 }}>PERIOD</div>
                <div style={{ fontFamily:"var(--mono)",fontSize:11,fontWeight:600,marginTop:3,color:parseFloat(periodReturn)>=0?"var(--green)":"var(--red)" }}>
                  {parseFloat(periodReturn)>=0?"+":""}{periodReturn}%
                </div>
              </div>
            )}
            <div style={{ marginLeft:"auto",display:"flex",alignItems:"center",fontFamily:"var(--mono)",fontSize:9,color:"var(--text-dim)" }}>
              {candles.length} candles · 🟢 Yahoo Finance
            </div>
          </div>
        </>
      )}
    </div>
  );
}


function TradingViewWidget({ symbol, interval = "D" }) {
  const containerRef = useRef(null);

  // Finnhub → TradingView symbol conversion
  const toTVSymbol = (s) => s.replace(/_/g, ""); // OANDA:USD_INR → OANDA:USDINR

  // Finnhub interval → TradingView interval (same notation, just pass through)
  const tvInterval = interval === "240" ? "240" : interval;
  const tvSymbol   = toTVSymbol(symbol);

  useEffect(() => {
    if (!containerRef.current) return;
    containerRef.current.innerHTML = "";

    const wrapper = document.createElement("div");
    wrapper.className = "tradingview-widget-container__widget";
    wrapper.style.cssText = "height:100%;width:100%;";
    containerRef.current.appendChild(wrapper);

    const script = document.createElement("script");
    script.type  = "text/javascript";
    script.src   = "https://s3.tradingview.com/external-embedding/embed-widget-advanced-chart.js";
    script.async = true;
    script.innerHTML = JSON.stringify({
      autosize: true,
      symbol: tvSymbol,
      interval: tvInterval,
      timezone: "Asia/Kolkata",
      theme: "dark",
      style: "1",
      locale: "en",
      withdateranges: true,
      hide_side_toolbar: false,
      allow_symbol_change: true,
      save_image: false,
      calendar: false,
      hide_volume: false,
      support_host: "https://www.tradingview.com",
    });
    containerRef.current.appendChild(script);

    return () => { if (containerRef.current) containerRef.current.innerHTML = ""; };
  }, [tvSymbol, tvInterval]);

  return (
    <div style={{ position: "relative", borderRadius: 10, overflow: "hidden", border: "1px solid rgba(0,212,255,0.15)" }}>
      <div
        ref={containerRef}
        className="tradingview-widget-container"
        style={{ height: 540, width: "100%" }}
      />
      <div style={{
        position: "absolute", bottom: 0, right: 0, left: 0,
        background: "linear-gradient(transparent, rgba(3,3,9,0.92))",
        padding: "6px 12px", display: "flex", alignItems: "center", gap: 6,
        fontFamily: "var(--mono)", fontSize: 9, color: "rgba(0,212,255,0.35)",
        pointerEvents: "none",
      }}>
        <span>📺 TradingView Advanced Chart — use the built-in search bar to find any of 100k+ symbols</span>
      </div>
    </div>
  );
}

/* ═══════════════════════════════════════════════════════════════
   CHART TAB — Finnhub + TradingView dual-mode
═══════════════════════════════════════════════════════════════ */
const FH_CATEGORIES = {
  "🇺🇸 US Tech":   [["AAPL","Apple"],["MSFT","Microsoft"],["GOOGL","Google"],["NVDA","NVIDIA"],["TSLA","Tesla"],["AMZN","Amazon"],["META","Meta"],["NFLX","Netflix"]],
  "🇮🇳 NSE Blue":  [["NSE:RELIANCE","Reliance"],["NSE:TCS","TCS"],["NSE:HDFCBANK","HDFC Bk"],["NSE:INFY","Infosys"],["NSE:SBIN","SBI"],["NSE:ICICIBANK","ICICI"],["NSE:WIPRO","Wipro"],["NSE:BAJFINANCE","Bajaj Fin"]],
  "🇮🇳 NSE Auto":  [["NSE:MARUTI","Maruti"],["NSE:TATAMOTORS","Tata Motors"],["NSE:BAJAJ_AUTO","Bajaj Auto"],["NSE:HEROMOTOCO","Hero Moto"],["NSE:EICHERMOT","Eicher"]],
  "🇮🇳 NSE IT":    [["NSE:TCS","TCS"],["NSE:INFY","Infosys"],["NSE:WIPRO","Wipro"],["NSE:HCLTECH","HCL Tech"],["NSE:TECHM","Tech M"],["NSE:LTIM","LTIM"]],
  "🇮🇳 NSE Pharma":[["NSE:SUNPHARMA","Sun Ph"],["NSE:DRREDDY","Dr Reddy"],["NSE:CIPLA","Cipla"],["NSE:DIVISLAB","Divi's"],["NSE:LUPIN","Lupin"]],
  "₿ Crypto":      [["BINANCE:BTCUSDT","BTC/USDT"],["BINANCE:ETHUSDT","ETH/USDT"],["BINANCE:BNBUSDT","BNB/USDT"],["BINANCE:SOLUSDT","SOL/USDT"],["BINANCE:ADAUSDT","ADA/USDT"]],
  "💱 Forex":       [["OANDA:USD_INR","USD/INR"],["OANDA:EUR_USD","EUR/USD"],["OANDA:GBP_USD","GBP/USD"],["OANDA:USD_JPY","USD/JPY"]],
};

const FH_RESOLUTIONS = [
  { label:"1m",  val:"1",  days:1  }, { label:"5m",  val:"5",  days:3  },
  { label:"15m", val:"15", days:5  }, { label:"30m", val:"30", days:10 },
  { label:"1H",  val:"60", days:30 }, { label:"4H",  val:"240",days:60 },
  { label:"1D",  val:"D",  days:180}, { label:"1W",  val:"W",  days:730},
];

function FinnhubChartTab({ apiKey }) {
  const [sym, setSym]           = useState("NSE:RELIANCE");
  const [res, setRes]           = useState("D");
  const [candles, setCandles]   = useState(null);
  const [quote, setQuote]       = useState(null);
  const [loading, setLoading]   = useState(false);
  const [error, setError]       = useState("");
  const [cat, setCat]           = useState("🇮🇳 NSE Blue");
  const [input, setInput]       = useState("");
  const [searchResults, setSearchResults] = useState([]);
  const [metrics, setMetrics]   = useState(null);
  // "finnhub" = custom SVG chart  |  "tv" = TradingView embedded widget
  const [chartMode, setChartMode] = useState("tv");

  const loadChart = useCallback(async (symbol, resolution) => {
    if (!apiKey) return;
    setLoading(true); setError(""); setCandles(null); setMetrics(null);
    const r = FH_RESOLUTIONS.find(r => r.val === resolution) || FH_RESOLUTIONS[6];
    const to = Math.floor(Date.now() / 1000);
    const from = to - r.days * 86400;
    const [c, q, m] = await Promise.all([
      FH.candle(symbol, resolution, from, to, apiKey),
      FH.quote(symbol, apiKey),
      FH.metrics(symbol, apiKey),
    ]);
    if (c?.s === "ok" && c.c?.length) {
      const data = c.t.map((ts, i) => ({
        date: new Date(ts * 1000).toLocaleDateString("en-IN", { month: "short", day: "numeric" }),
        o: c.o[i], h: c.h[i], l: c.l[i], c: c.c[i], v: c.v?.[i] || 0,
      })).slice(-120);
      setCandles(data); setQuote(q); setMetrics(m?.metric || null);
    } else {
      setError(`Finnhub has no candle data for "${symbol}" — auto-switched to TradingView.`);
      setChartMode("tv"); // ← AUTO FALLBACK
    }
    setLoading(false);
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [apiKey]);

  useEffect(() => {
    if (chartMode === "finnhub" && apiKey) loadChart(sym, res);
  }, [sym, res, chartMode, loadChart, apiKey]);

  const doSearch = async () => {
    if (!input.trim()) return;
    if (chartMode === "tv") {
      // In TV mode — navigate directly to TradingView, no popup/notification
      const cleaned = input.trim().toUpperCase();
      const tvSym = cleaned.replace(/_/g, "");
      window.location.href = `https://www.tradingview.com/chart/?symbol=${encodeURIComponent(tvSym)}`;
      setInput("");
      return;
    }
    if (!apiKey) return;
    const d = await FH.search(input.trim(), apiKey);
    if (d?.result) setSearchResults(d.result.slice(0, 8));
  };

  const fmtP = (n) => n == null ? "--" : n >= 1000 ? n.toLocaleString("en-IN", { maximumFractionDigits: 2 }) : n.toFixed(2);
  const isUp = quote ? quote.dp >= 0 : true;
  const last = candles?.[candles.length - 1];
  const first = candles?.[0];
  const periodReturn = (last && first) ? ((last.c - first.c) / first.c * 100).toFixed(2) : null;

  return (
    <div style={{ display: "flex", flexDirection: "column", gap: 14 }}>

      {/* ── TOP BAR ── */}
      <div style={{ display: "flex", gap: 10, flexWrap: "wrap", alignItems: "center" }}>

        {/* Chart Mode Toggle */}
        <div style={{ display: "flex", borderRadius: 8, overflow: "hidden", border: "1px solid rgba(0,212,255,0.25)", flexShrink: 0 }}>
          {[["tv","📺 TradingView"],["finnhub","📊 Finnhub SVG"]].map(([mode, label]) => (
            <button key={mode} onClick={() => { setChartMode(mode); if (mode === "finnhub" && apiKey) loadChart(sym, res); }}
              style={{
                padding: "8px 16px", border: "none", cursor: "pointer",
                fontFamily: "var(--mono)", fontSize: 11, fontWeight: 700, transition: "all .15s",
                background: chartMode === mode
                  ? (mode === "tv" ? "rgba(0,212,255,0.2)" : "rgba(232,184,75,0.2)")
                  : "rgba(255,255,255,0.04)",
                color: chartMode === mode
                  ? (mode === "tv" ? "var(--cyan)" : "var(--gold)")
                  : "var(--text-dim)",
              }}>{label}</button>
          ))}
        </div>

        {/* Symbol search */}
        <div style={{ display: "flex", gap: 6, flex: 1, minWidth: 240 }}>
          <input
            value={input}
            onChange={e => setInput(e.target.value)}
            onKeyDown={e => e.key === "Enter" && doSearch()}
            placeholder={chartMode === "tv"
              ? "Type any symbol → Enter  (e.g. NIFTY, RELIANCE, EURUSD, BTCUSDT)"
              : "Search Finnhub symbol (AAPL, NSE:RELIANCE)..."}
            style={{ flex: 1, fontFamily: "var(--mono)", fontSize: 12 }}
          />
          <button className="btn-gold" onClick={doSearch} style={{ padding: "6px 16px", fontSize: 11, flexShrink: 0 }}>🔍 GO</button>
        </div>

        {/* Live quote badge (Finnhub mode) */}
        {quote && chartMode === "finnhub" && (
          <div style={{ display: "flex", alignItems: "center", gap: 8, padding: "6px 14px", borderRadius: 8, background: "rgba(255,255,255,0.04)", border: "1px solid var(--border)" }}>
            <span style={{ fontFamily: "var(--mono)", fontSize: 11, color: "var(--text-dim)" }}>{sym}</span>
            <span style={{ fontFamily: "var(--mono)", fontSize: 16, fontWeight: 700, color: isUp ? "var(--green)" : "var(--red)" }}>{fmtP(quote.c)}</span>
            <span style={{ fontFamily: "var(--mono)", fontSize: 11, color: isUp ? "var(--green)" : "var(--red)" }}>
              {isUp ? "▲" : "▼"}{Math.abs(quote.dp).toFixed(2)}%
            </span>
          </div>
        )}

        {/* Current symbol display (TV mode) */}
        {chartMode === "tv" && (
          <div style={{ fontFamily: "var(--mono)", fontSize: 11, color: "var(--cyan)", padding: "6px 14px", borderRadius: 8, background: "rgba(0,212,255,0.06)", border: "1px solid rgba(0,212,255,0.15)" }}>
            📺 {sym}
          </div>
        )}
      </div>

      {/* ── SEARCH RESULTS (Finnhub mode) ── */}
      {searchResults.length > 0 && chartMode === "finnhub" && (
        <div style={{ display: "flex", flexDirection: "column", gap: 4, maxHeight: 160, overflowY: "auto", padding: "8px", background: "rgba(255,255,255,0.03)", borderRadius: 8, border: "1px solid var(--border)" }}>
          {searchResults.map((r, i) => (
            <div key={i} onClick={() => { setSym(r.symbol); setInput(""); setSearchResults([]); }}
              style={{ display: "flex", justifyContent: "space-between", padding: "5px 10px", borderRadius: 6, cursor: "pointer", border: "1px solid var(--border)", background: "rgba(0,0,0,0.2)" }}
              onMouseEnter={e => e.currentTarget.style.background = "rgba(0,212,255,0.08)"}
              onMouseLeave={e => e.currentTarget.style.background = "rgba(0,0,0,0.2)"}
            >
              <span style={{ fontFamily: "var(--mono)", fontSize: 11, color: "var(--cyan)" }}>{r.symbol}</span>
              <span style={{ fontFamily: "var(--sans)", fontSize: 10, color: "var(--text-dim)", maxWidth: 200, overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>{r.description}</span>
            </div>
          ))}
        </div>
      )}

      {/* ── RESOLUTION + CATEGORY (Finnhub mode only) ── */}
      {chartMode === "finnhub" && (
        <>
          <div style={{ display: "flex", alignItems: "center", gap: 8, flexWrap: "wrap" }}>
            <span style={{ fontFamily: "var(--gothic)", fontSize: 9, color: "var(--text-dim)", letterSpacing: 1.5 }}>TIMEFRAME:</span>
            <div style={{ display: "flex", gap: 3, background: "rgba(255,255,255,0.03)", padding: 3, borderRadius: 8, border: "1px solid var(--border)" }}>
              {FH_RESOLUTIONS.map(r => (
                <button key={r.val} onClick={() => setRes(r.val)} style={{
                  padding: "4px 12px", borderRadius: 6, border: "none", cursor: "pointer",
                  fontFamily: "var(--mono)", fontSize: 11, fontWeight: 600, transition: "all .15s",
                  background: res === r.val ? "rgba(0,212,255,0.16)" : "transparent",
                  color: res === r.val ? "var(--cyan)" : "var(--text-dim)",
                  boxShadow: res === r.val ? "0 0 0 1px rgba(0,212,255,0.3)" : "none",
                }}>{r.label}</button>
              ))}
            </div>
            {!apiKey && <span style={{ fontFamily: "var(--mono)", fontSize: 10, color: "var(--gold)" }}>⚠ Add Finnhub key in Settings</span>}
            <button className="btn-ghost" onClick={() => loadChart(sym, res)} style={{ fontSize: 10, padding: "4px 12px", marginLeft: "auto" }}>⟳ Refresh</button>
          </div>
          <div className="glass-card" style={{ padding: "10px 14px" }}>
            <div style={{ display: "flex", gap: 5, flexWrap: "wrap", marginBottom: 8, alignItems: "center" }}>
              <span style={{ fontFamily: "var(--mono)", fontSize: 9, color: "var(--text-dim)", letterSpacing: 1.5 }}>CATEGORY:</span>
              {Object.keys(FH_CATEGORIES).map(c => (
                <button key={c} onClick={() => setCat(c)} style={{
                  padding: "3px 10px", borderRadius: 20, border: "none", cursor: "pointer",
                  fontFamily: "var(--sans)", fontSize: 10, transition: "all .12s",
                  background: cat === c ? "rgba(0,212,255,0.14)" : "rgba(255,255,255,0.04)",
                  color: cat === c ? "var(--cyan)" : "var(--text-dim)",
                }}>{c}</button>
              ))}
            </div>
            <div style={{ display: "flex", gap: 5, flexWrap: "wrap" }}>
              {FH_CATEGORIES[cat]?.map(([s, label]) => (
                <button key={s} onClick={() => setSym(s)} style={{
                  padding: "4px 12px", borderRadius: 7, border: "none", cursor: "pointer",
                  fontFamily: "var(--mono)", fontSize: 11, fontWeight: 600, transition: "all .12s",
                  background: sym === s ? "linear-gradient(135deg,rgba(232,184,75,0.22),rgba(232,184,75,0.08))" : "rgba(255,255,255,0.04)",
                  color: sym === s ? "var(--gold)" : "var(--text)",
                  boxShadow: sym === s ? "0 0 0 1px rgba(232,184,75,0.3)" : "none",
                }}>{label}</button>
              ))}
            </div>
          </div>
        </>
      )}

      {/* ── TRADINGVIEW WIDGET ── */}
      {chartMode === "tv" && (
        <>
          {/* Quick-access buttons for TV mode */}
          <div className="glass-card" style={{ padding: "10px 14px" }}>
            <div style={{ display: "flex", gap: 5, flexWrap: "wrap", marginBottom: 8, alignItems: "center" }}>
              <span style={{ fontFamily: "var(--mono)", fontSize: 9, color: "var(--cyan)", letterSpacing: 1.5 }}>QUICK SELECT:</span>
              {Object.keys(FH_CATEGORIES).map(c => (
                <button key={c} onClick={() => setCat(c)} style={{
                  padding: "3px 10px", borderRadius: 20, border: "none", cursor: "pointer",
                  fontFamily: "var(--sans)", fontSize: 10, transition: "all .12s",
                  background: cat === c ? "rgba(0,212,255,0.14)" : "rgba(255,255,255,0.04)",
                  color: cat === c ? "var(--cyan)" : "var(--text-dim)",
                }}>{c}</button>
              ))}
            </div>
            <div style={{ display: "flex", gap: 5, flexWrap: "wrap" }}>
              {FH_CATEGORIES[cat]?.map(([s, label]) => (
                <button key={s} onClick={() => {
                  const tvSym = s.replace(/_/g, "");
                  window.location.href = `https://www.tradingview.com/chart/?symbol=${encodeURIComponent(tvSym)}`;
                }} style={{
                  padding: "4px 12px", borderRadius: 7, border: "none", cursor: "pointer",
                  fontFamily: "var(--mono)", fontSize: 11, fontWeight: 600, transition: "all .12s",
                  background: "rgba(255,255,255,0.04)",
                  color: "var(--text)",
                }}>{label}</button>
              ))}
            </div>
          </div>
        </>
      )}

      {/* ── FINNHUB CHART ── */}
      {chartMode === "finnhub" && (
        <div className="glass-card" style={{ padding: "16px 16px 8px" }}>
          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 12 }}>
            <div style={{ fontFamily: "var(--mono)", fontSize: 13, color: "var(--cyan)", fontWeight: 700 }}>{sym}</div>
            <div style={{ fontFamily: "var(--gothic)", fontSize: 9, color: "var(--text-dim)", letterSpacing: 2 }}>
              FINNHUB · {FH_RESOLUTIONS.find(r => r.val === res)?.label} · CANDLESTICK + SMA20 + VOLUME
            </div>
          </div>
          {loading && (
            <div style={{ height: 400, display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", gap: 16 }}>
              <div className="spin" style={{ width: 36, height: 36, border: "3px solid rgba(0,212,255,0.1)", borderTopColor: "var(--cyan)", borderRadius: "50%" }} />
              <div style={{ fontFamily: "var(--gothic)", fontSize: 11, color: "var(--cyan)", letterSpacing: 2 }}>FETCHING CANDLES FROM FINNHUB...</div>
            </div>
          )}
          {error && !loading && (
            <div style={{ padding: "30px 20px", textAlign: "center" }}>
              <div style={{ color: "var(--gold)", fontFamily: "var(--mono)", fontSize: 12, marginBottom: 12 }}>⚠ {error}</div>
              <button onClick={() => setChartMode("tv")} style={{
                padding: "8px 20px", borderRadius: 8, border: "1px solid rgba(0,212,255,0.3)",
                background: "rgba(0,212,255,0.1)", color: "var(--cyan)", cursor: "pointer",
                fontFamily: "var(--mono)", fontSize: 11, fontWeight: 700,
              }}>📺 Open in TradingView (embedded)</button>
            </div>
          )}
          {candles && !loading && (
            <>
              <CandlestickSVG data={candles} width={1100} height={340} />
              <VolumeSVG data={candles} width={1100} height={56} />
              <div style={{ display: "flex", gap: 10, marginTop: 10, flexWrap: "wrap" }}>
                {(() => {
                  const last = candles[candles.length - 1];
                  return [["Open",last.o],["High",last.h],["Low",last.l],["Close",last.c],["Volume",last.v ? (last.v / 1e6).toFixed(2) + "M" : "--"]].map(([l, v]) => (
                    <div key={l} style={{ background: "rgba(255,255,255,0.03)", borderRadius: 7, padding: "6px 12px", textAlign: "center" }}>
                      <div style={{ fontFamily: "var(--gothic)", fontSize: 8, color: "var(--text-dim)", letterSpacing: 1.5 }}>{l}</div>
                      <div style={{ fontFamily: "var(--mono)", fontSize: 11, color: "var(--text)", fontWeight: 600, marginTop: 3 }}>{typeof v === "number" ? fmtP(v) : v}</div>
                    </div>
                  ));
                })()}
                {periodReturn && (
                  <div style={{ background: "rgba(255,255,255,0.03)", borderRadius: 7, padding: "6px 12px", textAlign: "center" }}>
                    <div style={{ fontFamily: "var(--gothic)", fontSize: 8, color: "var(--text-dim)", letterSpacing: 1.5 }}>PERIOD</div>
                    <div style={{ fontFamily: "var(--mono)", fontSize: 11, fontWeight: 600, marginTop: 3, color: parseFloat(periodReturn) >= 0 ? "var(--green)" : "var(--red)" }}>
                      {parseFloat(periodReturn) >= 0 ? "+" : ""}{periodReturn}%
                    </div>
                  </div>
                )}
                <div style={{ marginLeft: "auto", display: "flex", alignItems: "center", fontFamily: "var(--mono)", fontSize: 9, color: "var(--text-dim)" }}>
                  {candles.length} candles · ⚡ Finnhub
                </div>
              </div>
              {metrics && (
                <div style={{ display: "flex", gap: 16, flexWrap: "wrap", marginTop: 12, paddingTop: 10, borderTop: "1px solid var(--border)" }}>
                  {[["P/E",metrics["peExclExtraTTM"]],["EPS",metrics["epsExclExtraItemsTTM"]],["52W High",metrics["52WeekHigh"]],["52W Low",metrics["52WeekLow"]],["Beta",metrics["beta"]]].filter(([,v])=>v!=null).map(([l,v])=>(
                    <div key={l}>
                      <div style={{ fontFamily: "var(--sans)", fontSize: 9, color: "var(--text-dim)" }}>{l}</div>
                      <div style={{ fontFamily: "var(--mono)", fontSize: 11, color: "var(--text)", fontWeight: 600 }}>{typeof v === "number" ? v.toFixed(2) : v}</div>
                    </div>
                  ))}
                </div>
              )}
            </>
          )}
        </div>
      )}

    </div>
  );
}

/* ═══════════════════════════════════════════════════════════════
   MARKET OVERVIEW — 100% Finnhub
═══════════════════════════════════════════════════════════════ */
const FH_OVERVIEW_GROUPS = [
  { label:"🇺🇸 US Indices / ETFs", syms:[["SPY","S&P 500 ETF"],["QQQ","NASDAQ ETF"],["DIA","Dow Jones ETF"],["IWM","Russell 2000"]] },
  { label:"🇮🇳 Indian Blue-chip",   syms:[["NSE:RELIANCE","Reliance"],["NSE:TCS","TCS"],["NSE:HDFCBANK","HDFC Bk"],["NSE:INFY","Infosys"],["NSE:SBIN","SBI"],["NSE:ICICIBANK","ICICI"],["NSE:TATAMOTORS","Tata Motors"],["NSE:BAJFINANCE","Bajaj Fin"]] },
  { label:"🇺🇸 US Mega-Cap",        syms:[["AAPL","Apple"],["MSFT","Microsoft"],["NVDA","NVIDIA"],["GOOGL","Google"],["AMZN","Amazon"],["META","Meta"],["TSLA","Tesla"]] },
  { label:"₿ Crypto",              syms:[["BINANCE:BTCUSDT","BTC/USDT"],["BINANCE:ETHUSDT","ETH/USDT"],["BINANCE:BNBUSDT","BNB/USDT"],["BINANCE:SOLUSDT","SOL/USDT"],["BINANCE:ADAUSDT","ADA/USDT"]] },
  { label:"💱 Forex",               syms:[["OANDA:USD_INR","USD/INR"],["OANDA:EUR_USD","EUR/USD"],["OANDA:GBP_USD","GBP/USD"],["OANDA:USD_JPY","USD/JPY"]] },
  { label:"🏅 Commodities",         syms:[["OANDA:XAU_USD","Gold"],["OANDA:XAG_USD","Silver"],["OANDA:BRENT_CRUDE_OIL","Brent Oil"],["OANDA:NATURAL_GAS","Nat Gas"]] },
];

function FinnhubMarketOverview({ apiKey }) {
  const [quotes, setQuotes] = useState({});
  const [loading, setLoading] = useState(false);
  const [lastUpd, setLastUpd] = useState(null);

  const fetchAll = useCallback(async () => {
    if (!apiKey) return;
    setLoading(true);
    const allSyms = FH_OVERVIEW_GROUPS.flatMap(g => g.syms.map(([s]) => s));
    const chunks = [];
    for (let i = 0; i < allSyms.length; i += 6) chunks.push(allSyms.slice(i, i + 6));
    const res = {};
    for (const chunk of chunks) {
      await Promise.all(chunk.map(async s => {
        const q = await FH.quote(s, apiKey);
        if (q) res[s] = q;
      }));
      await new Promise(r => setTimeout(r, 250));
    }
    setQuotes(res); setLastUpd(new Date()); setLoading(false);
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [apiKey]);

  useEffect(() => { fetchAll(); const iv = setInterval(fetchAll, 60000); return () => clearInterval(iv); }, [fetchAll]);

  const fmtP = n => n == null ? "--" : n >= 1000 ? n.toLocaleString("en-IN", { maximumFractionDigits: 2 }) : n.toFixed(2);

  return (
    <div style={{ display: "flex", flexDirection: "column", gap: 16 }}>
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", flexWrap: "wrap", gap: 8 }}>
        <div style={{ fontFamily: "var(--gothic)", fontSize: 9, color: "var(--text-dim)", letterSpacing: 2 }}>◈ LIVE MARKET OVERVIEW · FINNHUB{lastUpd ? ` · ${lastUpd.toLocaleTimeString("en-IN")}` : ""}</div>
        <button className="btn-ghost" onClick={fetchAll} disabled={loading} style={{ fontSize: 10, padding: "5px 12px" }}>{loading ? "⟳ Refreshing..." : "⟳ Refresh"}</button>
      </div>

      {FH_OVERVIEW_GROUPS.map(g => (
        <div key={g.label} className="glass-card" style={{ padding: "14px 18px" }}>
          <div style={{ fontFamily: "var(--gothic)", fontSize: 9, color: "var(--text-dim)", letterSpacing: 2, marginBottom: 12 }}>{g.label}</div>
          <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(160px, 1fr))", gap: 8 }}>
            {g.syms.map(([s, label]) => {
              const q = quotes[s];
              const isUp = q ? q.dp >= 0 : null;
              const col = isUp === null ? "var(--text-dim)" : isUp ? "var(--green)" : "var(--red)";
              return (
                <div key={s} style={{ background: "rgba(255,255,255,0.03)", borderRadius: 10, padding: "10px 14px", border: `1px solid ${isUp === null ? "rgba(255,255,255,0.06)" : isUp ? "rgba(14,204,109,0.15)" : "rgba(240,64,96,0.15)"}` }}>
                  <div style={{ fontFamily: "var(--gothic)", fontSize: 9, color: "var(--text-dim)", letterSpacing: 1, marginBottom: 6 }}>{label}</div>
                  <div style={{ fontFamily: "var(--mono)", fontSize: 15, fontWeight: 700, color: col, lineHeight: 1 }}>{q ? fmtP(q.c) : <span style={{ opacity: .2 }}>—</span>}</div>
                  <div style={{ fontFamily: "var(--mono)", fontSize: 10, color: col, marginTop: 5, display: "flex", alignItems: "center", gap: 4 }}>
                    {q ? (
                      <span style={{ background: isUp ? "rgba(14,204,109,0.1)" : "rgba(240,64,96,0.1)", padding: "2px 7px", borderRadius: 4 }}>
                        {isUp ? "▲" : "▼"}{Math.abs(q.dp).toFixed(2)}%
                      </span>
                    ) : <span style={{ opacity: .2 }}>---</span>}
                  </div>
                </div>
              );
            })}
          </div>
        </div>
      ))}

      {!apiKey && (
        <div className="glass-card" style={{ borderColor: "var(--gold)", textAlign: "center", padding: "40px 20px" }}>
          <div style={{ fontSize: 32, marginBottom: 10 }}>🔑</div>
          <div style={{ fontFamily: "var(--serif)", fontSize: 18, color: "var(--text)" }}>Add Finnhub API Key</div>
          <div style={{ fontFamily: "var(--sans)", fontSize: 12, color: "var(--text-dim)", marginTop: 6 }}>Go to Settings and enter your free Finnhub key to see live prices.</div>
        </div>
      )}
    </div>
  );
}

/* ═══════════════════════════════════════════════════════════════
   EARNINGS + IPO CALENDAR — 100% Finnhub
═══════════════════════════════════════════════════════════════ */
function FinnhubCalendarTab({ apiKey }) {
  const [view, setView]       = useState("earnings");
  const [earnings, setEarnings] = useState([]);
  const [ipos, setIpos]       = useState([]);
  const [loading, setLoading] = useState(false);
  const [loaded, setLoaded]   = useState(false);

  const fetchData = useCallback(async () => {
    if (!apiKey) return;
    setLoading(true);
    const now = new Date();
    const from = now.toISOString().slice(0, 10);
    const to   = new Date(now.getTime() + 30 * 86400000).toISOString().slice(0, 10);
    const [ea, ip] = await Promise.all([FH.earnings(from, to, apiKey), FH.ipo(from, to, apiKey)]);
    if (ea?.earningsCalendar) setEarnings(ea.earningsCalendar.slice(0, 40));
    if (ip?.ipoCalendar) setIpos(ip.ipoCalendar.slice(0, 30));
    setLoaded(true); setLoading(false);
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [apiKey]);

  useEffect(() => { fetchData(); }, [fetchData]);

  const fmtDate = d => { try { return new Date(d).toLocaleDateString("en-IN", { day: "2-digit", month: "short", year: "numeric" }); } catch { return d; } };

  return (
    <div style={{ display: "flex", flexDirection: "column", gap: 14 }}>
      <div style={{ display: "flex", gap: 4, background: "rgba(255,255,255,0.04)", borderRadius: 10, padding: 3, border: "1px solid var(--border)", width: "fit-content" }}>
        {[["earnings","📅 Earnings Calendar"],["ipo","🚀 IPO Calendar"]].map(([id, label]) => (
          <button key={id} onClick={() => setView(id)} style={{
            padding: "7px 18px", borderRadius: 8, cursor: "pointer",
            fontFamily: "var(--sans)", fontWeight: 600, fontSize: 12, transition: "all .2s",
            background: view === id ? "rgba(0,212,255,0.12)" : "transparent",
            color: view === id ? "var(--cyan)" : "var(--text-dim)",
            border: view === id ? "1px solid rgba(0,212,255,0.25)" : "1px solid transparent",
          }}>{label}</button>
        ))}
        <button className="btn-ghost" onClick={fetchData} style={{ fontSize: 10, padding: "5px 14px" }}>⟳</button>
      </div>

      {!apiKey && <div className="glass-card" style={{ padding: "30px", textAlign: "center", color: "var(--gold)", fontFamily: "var(--mono)", fontSize: 12 }}>🔑 Add Finnhub API key in Settings</div>}
      {loading && <div style={{ textAlign: "center", padding: "40px", fontFamily: "var(--mono)", fontSize: 12, color: "var(--text-dim)" }}>Fetching calendar data...</div>}

      {view === "earnings" && loaded && !loading && (
        <div className="glass-card" style={{ padding: 0, overflow: "hidden" }}>
          <div style={{ display: "grid", gridTemplateColumns: "1.4fr 1fr 1fr 1fr 1fr", padding: "10px 18px", borderBottom: "1px solid var(--border)", background: "rgba(255,255,255,0.02)" }}>
            {["Symbol","Date","EPS Est.","EPS Actual","Revenue Est."].map(h => (
              <div key={h} style={{ fontFamily: "var(--gothic)", fontSize: 9, color: "var(--text-dim)", letterSpacing: 1.5 }}>{h}</div>
            ))}
          </div>
          {earnings.length === 0 && <div style={{ padding: "30px", textAlign: "center", color: "var(--text-dim)", fontFamily: "var(--mono)", fontSize: 12 }}>No upcoming earnings found.</div>}
          {earnings.map((e, i) => (
            <div key={i} style={{ display: "grid", gridTemplateColumns: "1.4fr 1fr 1fr 1fr 1fr", padding: "11px 18px", borderBottom: "1px solid rgba(255,255,255,0.03)", transition: "background .12s" }}
              onMouseEnter={ev => ev.currentTarget.style.background = "rgba(255,255,255,0.03)"}
              onMouseLeave={ev => ev.currentTarget.style.background = "transparent"}
            >
              <div style={{ fontFamily: "var(--mono)", fontSize: 12, fontWeight: 700, color: "var(--text)" }}>{e.symbol}</div>
              <div style={{ fontFamily: "var(--mono)", fontSize: 11, color: "var(--text-dim)" }}>{fmtDate(e.date)}</div>
              <div style={{ fontFamily: "var(--mono)", fontSize: 11, color: "var(--text-mid)" }}>{e.epsEstimate ?? "--"}</div>
              <div style={{ fontFamily: "var(--mono)", fontSize: 11, color: e.epsActual != null ? (e.epsActual >= (e.epsEstimate || 0) ? "var(--green)" : "var(--red)") : "var(--text-dim)" }}>{e.epsActual ?? "--"}</div>
              <div style={{ fontFamily: "var(--mono)", fontSize: 11, color: "var(--text-dim)" }}>{e.revenueEstimate ? (e.revenueEstimate / 1e9).toFixed(2) + "B" : "--"}</div>
            </div>
          ))}
        </div>
      )}

      {view === "ipo" && loaded && !loading && (
        <div className="glass-card" style={{ padding: 0, overflow: "hidden" }}>
          <div style={{ display: "grid", gridTemplateColumns: "1.2fr 1fr 0.8fr 0.8fr 1fr", padding: "10px 18px", borderBottom: "1px solid var(--border)", background: "rgba(255,255,255,0.02)" }}>
            {["Company","Symbol","Date","Price","Shares"].map(h => (
              <div key={h} style={{ fontFamily: "var(--gothic)", fontSize: 9, color: "var(--text-dim)", letterSpacing: 1.5 }}>{h}</div>
            ))}
          </div>
          {ipos.length === 0 && <div style={{ padding: "30px", textAlign: "center", color: "var(--text-dim)", fontFamily: "var(--mono)", fontSize: 12 }}>No upcoming IPOs found.</div>}
          {ipos.map((ip, i) => (
            <div key={i} style={{ display: "grid", gridTemplateColumns: "1.2fr 1fr 0.8fr 0.8fr 1fr", padding: "11px 18px", borderBottom: "1px solid rgba(255,255,255,0.03)", transition: "background .12s" }}
              onMouseEnter={ev => ev.currentTarget.style.background = "rgba(255,255,255,0.03)"}
              onMouseLeave={ev => ev.currentTarget.style.background = "transparent"}
            >
              <div style={{ fontFamily: "var(--sans)", fontSize: 12, color: "var(--text)", fontWeight: 500, overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>{ip.name}</div>
              <div style={{ fontFamily: "var(--mono)", fontSize: 11, color: "var(--cyan)" }}>{ip.symbol}</div>
              <div style={{ fontFamily: "var(--mono)", fontSize: 11, color: "var(--text-dim)" }}>{fmtDate(ip.date)}</div>
              <div style={{ fontFamily: "var(--mono)", fontSize: 11, color: "var(--gold)" }}>{ip.price ? "$" + ip.price : "--"}</div>
              <div style={{ fontFamily: "var(--mono)", fontSize: 11, color: "var(--text-dim)" }}>{ip.numberOfShares ? (ip.numberOfShares / 1e6).toFixed(1) + "M" : "--"}</div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

